-- Minute Mantra — 365 Mantra Records
-- Generated by scripts/export-seed-files.js

INSERT INTO mantras
  (day_of_year, original_script, transliteration, english_translation,
   tradition, intention, phonetic_guide, audio_filename, go_deeper_url,
   go_deeper_teaser, context_note, sacred_geometry_type)
VALUES
  (1, 'ॐ नमः शिवाय', 'Om Namah Shivaya', 'I bow to Shiva — the auspicious one, the pure consciousness within all.', 'vedic_shiva', 'Purification', 'OHM nah-MAH shih-VAH-yah', 'mantra-001.mp3', 'https://paulwagner.com', 'Why Om Namah Shivaya changes your nervous system →', 'The Panchakshara mantra — five sacred syllables representing the five elements. The most widely chanted Shaivite mantra.', 'seed_of_life'),
  (2, 'ॐ त्र्यम्बकं यजामहे', 'Om Tryambakam Yajamahe', 'We worship the three-eyed one who nourishes and liberates us from the bondage of death.', 'vedic_shiva', 'Healing', 'OHM tree-AHM-bah-kahm yah-JAH-mah-hay', 'mantra-002.mp3', 'https://paulwagner.com', 'The science of the Maha Mrityunjaya mantra →', 'The Maha Mrityunjaya mantra from the Rigveda. Chanted for healing, longevity, and liberation from fear.', 'seed_of_life'),
  (3, 'ॐ नमः शिवाय शुभम् शुभम् करु', 'Om Namah Shivaya Shubham Shubham Kuru', 'Om, I bow to Shiva — bring auspiciousness, bring auspiciousness.', 'vedic_shiva', 'Blessings', 'OHM nah-MAH shih-VAH-yah SHOO-bahm SHOO-bahm KOO-roo', 'mantra-003.mp3', 'https://paulwagner.com', 'Morning mantras that shift your entire day →', 'An expanded form of the Panchakshara invoking blessings and positive energy into daily life.', 'lotus'),
  (4, 'शिवोऽहम् शिवोऽहम्', 'Shivo\'ham Shivo\'ham', 'I am Shiva. I am Shiva.', 'vedic_shiva', 'Self-realization', 'shih-VOH-hahm shih-VOH-hahm', 'mantra-004.mp3', 'https://paulwagner.com', 'The Nirvana Shatakam: Shankara\'s greatest poem →', 'From Adi Shankaracharya\'s Nirvana Shatakam. A direct affirmation of identity with pure consciousness.', 'sri_yantra'),
  (5, 'ॐ हौं जूं सः', 'Om Haum Jum Sah', 'Om — the seed of Shiva — the seed of life — I am that.', 'vedic_shiva', 'Vitality', 'OHM howm joom sah', 'mantra-005.mp3', 'https://paulwagner.com', 'Bija mantras: seeds of cosmic power →', 'The Maha Mrityunjaya bija mantra. Haum is the seed syllable of Shiva; Jum is the seed of life force.', 'seed_of_life'),
  (6, 'ॐ नमः शिवाय नमः', 'Om Namah Shivaya Namah', 'Om, I bow to Shiva, I bow.', 'vedic_shiva', 'Devotion', 'OHM nah-MAH shih-VAH-yah nah-MAH', 'mantra-006.mp3', 'https://paulwagner.com', 'What surrender really means in spiritual practice →', 'An extended form adding a second namah — deepening the gesture of surrender and reverence.', 'seed_of_life'),
  (7, 'ॐ शं शिवाय नमः', 'Om Sham Shivaya Namah', 'Om, I bow to Shiva who brings peace and auspiciousness.', 'vedic_shiva', 'Peace', 'OHM shahm shih-VAH-yah nah-MAH', 'mantra-007.mp3', 'https://paulwagner.com', 'How mantra activates the parasympathetic nervous system →', 'Sham is the bija of peace and cooling. This mantra soothes the nervous system and calms mental agitation.', 'lotus'),
  (8, 'ॐ शिव शक्ति नमः', 'Om Shiva Shakti Namah', 'Om, I bow to the union of Shiva and Shakti — consciousness and energy.', 'vedic_shiva', 'Balance', 'OHM SHIH-vah SHAHK-tee nah-MAH', 'mantra-008.mp3', 'https://paulwagner.com', 'The sacred marriage: Shiva and Shakti explained →', 'Shiva is pure awareness; Shakti is the dynamic energy of creation. Their union is the source of all existence.', 'sri_yantra'),
  (9, 'ॐ महादेवाय नमः', 'Om Mahadevaya Namah', 'Om, I bow to the Great God — the supreme deity.', 'vedic_shiva', 'Reverence', 'OHM mah-hah-DAY-vah-yah nah-MAH', 'mantra-009.mp3', 'https://paulwagner.com', 'The 108 names of Shiva and their meanings →', 'Mahadeva means "Great God" — one of Shiva\'s most exalted names, honoring his supremacy among the devas.', 'seed_of_life'),
  (10, 'ॐ नीलकण्ठाय नमः', 'Om Nilakanthaya Namah', 'Om, I bow to the blue-throated one who swallowed poison to save the world.', 'vedic_shiva', 'Courage', 'OHM nee-lah-KAHN-thah-yah nah-MAH', 'mantra-010.mp3', 'https://paulwagner.com', 'The churning of the ocean: Shiva\'s greatest sacrifice →', 'Nilakantha — "blue throat" — refers to Shiva holding the cosmic poison in his throat to protect all beings. A mantra of fearless compassion.', 'lotus'),
  (11, 'ॐ नटराजाय नमः', 'Om Natarajaya Namah', 'Om, I bow to the Lord of the Cosmic Dance.', 'vedic_shiva', 'Flow', 'OHM nah-tah-RAH-jah-yah nah-MAH', 'mantra-011.mp3', 'https://paulwagner.com', 'Nataraja: the physics of the cosmic dance →', 'Nataraja — Shiva as the cosmic dancer — represents the continuous cycles of creation, preservation, and dissolution.', 'flower_of_life'),
  (12, 'ॐ पशुपतये नमः', 'Om Pashupataye Namah', 'Om, I bow to the Lord of all creatures.', 'vedic_shiva', 'Compassion', 'OHM pah-shoo-PAH-tah-yay nah-MAH', 'mantra-012.mp3', 'https://paulwagner.com', 'Shiva as the original animal protector →', 'Pashupati — "Lord of animals" — honors Shiva as the protector of all sentient beings, from the smallest creature to the greatest.', 'seed_of_life'),
  (13, 'ॐ भवाय नमः', 'Om Bhavaya Namah', 'Om, I bow to the source of all existence.', 'vedic_shiva', 'Gratitude', 'OHM bhah-VAH-yah nah-MAH', 'mantra-013.mp3', 'https://paulwagner.com', 'The miracle of existence: why being here matters →', 'Bhava means "being" or "existence." This name honors Shiva as the ground of all being — the very fact that anything exists at all.', 'lotus'),
  (14, 'ॐ रुद्राय नमः', 'Om Rudraya Namah', 'Om, I bow to Rudra — the fierce one who removes suffering.', 'vedic_shiva', 'Release', 'OHM ROOD-rah-yah nah-MAH', 'mantra-014.mp3', 'https://paulwagner.com', 'Rudra: the sacred power of divine anger →', 'Rudra is Shiva\'s Vedic form — the howling storm god who destroys what no longer serves. Chanting this releases stuck energy.', 'sri_yantra'),
  (15, 'ॐ शंकराय नमः', 'Om Shankaraya Namah', 'Om, I bow to the one who brings blessings and auspiciousness.', 'vedic_shiva', 'Blessings', 'OHM shahn-KAH-rah-yah nah-MAH', 'mantra-015.mp3', 'https://paulwagner.com', 'Opening to grace: the practice of receptivity →', 'Shankara — "conferring happiness" — is one of Shiva\'s most beloved names. This mantra opens the heart to receive grace.', 'seed_of_life'),
  (16, 'ॐ गिरीशाय नमः', 'Om Girishaya Namah', 'Om, I bow to the Lord of the mountains.', 'vedic_shiva', 'Stability', 'OHM gih-REE-shah-yah nah-MAH', 'mantra-016.mp3', 'https://paulwagner.com', 'Mount Kailash: the axis of the world →', 'Girisha — "mountain lord" — honors Shiva\'s home on Mount Kailash. Mountains represent the immovable foundation of consciousness.', 'lotus'),
  (17, 'ॐ भोलेनाथाय नमः', 'Om Bholenathaya Namah', 'Om, I bow to the innocent lord — the simple-hearted one.', 'vedic_shiva', 'Simplicity', 'OHM boh-lay-NAH-thah-yah nah-MAH', 'mantra-017.mp3', 'https://paulwagner.com', 'Why Shiva is the easiest god to please →', 'Bholenath — "innocent lord" — is a beloved folk name for Shiva. He is easily pleased by sincere devotion, however simple.', 'seed_of_life'),
  (18, 'ॐ विश्वनाथाय नमः', 'Om Vishwanathaya Namah', 'Om, I bow to the Lord of the universe.', 'vedic_shiva', 'Expansion', 'OHM vish-wah-NAH-thah-yah nah-MAH', 'mantra-018.mp3', 'https://paulwagner.com', 'Varanasi: the city where Shiva never sleeps →', 'Vishwanath — "Lord of all worlds" — is the presiding deity of Varanasi, the oldest living city on earth.', 'flower_of_life'),
  (19, 'ॐ आशुतोषाय नमः', 'Om Ashutoshaya Namah', 'Om, I bow to the one who is quickly satisfied.', 'vedic_shiva', 'Contentment', 'OHM ah-shoo-TOH-shah-yah nah-MAH', 'mantra-019.mp3', 'https://paulwagner.com', 'The art of contentment: Santosha in daily life →', 'Ashutosh — "quickly pleased" — teaches that Shiva asks for nothing more than sincere love. Contentment is the highest offering.', 'lotus'),
  (20, 'ॐ त्रिलोचनाय नमः', 'Om Trilochanaya Namah', 'Om, I bow to the three-eyed one who sees past, present, and future.', 'vedic_shiva', 'Clarity', 'OHM tree-loh-CHAH-nah-yah nah-MAH', 'mantra-020.mp3', 'https://paulwagner.com', 'Activating your third eye through mantra →', 'Shiva\'s third eye represents the eye of wisdom — the ability to see beyond duality into the nature of reality.', 'sri_yantra'),
  (21, 'ॐ सदाशिवाय नमः', 'Om Sadashivaya Namah', 'Om, I bow to the eternally auspicious one.', 'vedic_shiva', 'Eternity', 'OHM sah-dah-SHIH-vah-yah nah-MAH', 'mantra-021.mp3', 'https://paulwagner.com', 'What it means to touch the eternal →', 'Sadashiva — "always auspicious" — represents the eternal, unchanging aspect of Shiva beyond time and space.', 'seed_of_life'),
  (22, 'ॐ उमापतये नमः', 'Om Umapataye Namah', 'Om, I bow to the consort of Uma — the divine feminine.', 'vedic_shiva', 'Love', 'OHM oo-mah-PAH-tah-yay nah-MAH', 'mantra-022.mp3', 'https://paulwagner.com', 'Shiva and Parvati: the original love story →', 'Uma (Parvati) is Shiva\'s beloved. This mantra honors the sacred partnership of masculine and feminine principles.', 'lotus'),
  (23, 'ॐ कपर्दिने नमः', 'Om Kapardine Namah', 'Om, I bow to the matted-haired one who holds the Ganges.', 'vedic_shiva', 'Purification', 'OHM kah-pahr-DEE-nay nah-MAH', 'mantra-023.mp3', 'https://paulwagner.com', 'The Ganga in Shiva\'s hair: a story of grace →', 'Shiva\'s matted hair (jata) holds the sacred river Ganga, purifying all who touch her waters.', 'seed_of_life'),
  (24, 'ॐ भस्माङ्गाय नमः', 'Om Bhasmangaya Namah', 'Om, I bow to the one adorned with sacred ash.', 'vedic_shiva', 'Impermanence', 'OHM bahsh-MAHN-gah-yah nah-MAH', 'mantra-024.mp3', 'https://paulwagner.com', 'Sacred ash and the wisdom of impermanence →', 'Shiva smears himself with ash from cremation grounds — a reminder that all bodies return to ash. This mantra cultivates non-attachment.', 'lotus'),
  (25, 'ॐ गङ्गाधराय नमः', 'Om Gangadharaya Namah', 'Om, I bow to the one who holds the sacred Ganga in his locks.', 'vedic_shiva', 'Grace', 'OHM gahn-gah-DHAH-rah-yah nah-MAH', 'mantra-025.mp3', 'https://paulwagner.com', 'How Shiva saved the earth with his hair →', 'When the heavenly Ganga descended to earth, Shiva caught her in his hair to prevent the earth from being destroyed by her force.', 'flower_of_life'),
  (26, 'ॐ जटाधराय नमः', 'Om Jatadharaya Namah', 'Om, I bow to the one with matted locks of an ascetic.', 'vedic_shiva', 'Renunciation', 'OHM jah-tah-DHAH-rah-yah nah-MAH', 'mantra-026.mp3', 'https://paulwagner.com', 'Tapas: the sacred fire of spiritual discipline →', 'The matted hair (jata) represents the renunciation of worldly vanity and the accumulation of tapas — spiritual heat.', 'seed_of_life'),
  (27, 'ॐ कालेश्वराय नमः', 'Om Kaleshwaraya Namah', 'Om, I bow to the Lord of time who transcends all time.', 'vedic_shiva', 'Presence', 'OHM kah-laysh-WAH-rah-yah nah-MAH', 'mantra-027.mp3', 'https://paulwagner.com', 'Living in the eternal now: Shiva\'s greatest teaching →', 'Kaleshwara — "Lord of time" — reminds us that Shiva is both the master of time and beyond it. This mantra anchors us in the eternal now.', 'sri_yantra'),
  (28, 'ॐ ईशानाय नमः', 'Om Ishanaya Namah', 'Om, I bow to the ruler of the northeast — the direction of grace.', 'vedic_shiva', 'Wisdom', 'OHM ee-SHAH-nah-yah nah-MAH', 'mantra-028.mp3', 'https://paulwagner.com', 'The five faces of Shiva: Panchamukha explained →', 'Ishana is Shiva\'s form ruling the northeast direction — associated with wisdom, grace, and the transmission of spiritual knowledge.', 'lotus'),
  (29, 'ॐ तत्पुरुषाय नमः', 'Om Tatpurushaya Namah', 'Om, I bow to the supreme being — the highest self.', 'vedic_shiva', 'Self-realization', 'OHM taht-poo-ROO-shah-yah nah-MAH', 'mantra-029.mp3', 'https://paulwagner.com', 'Tat tvam asi: you are that →', 'Tatpurusha — "that supreme person" — is the east-facing form of Shiva, representing the transcendent self beyond ego.', 'sri_yantra'),
  (30, 'ॐ अघोराय नमः', 'Om Aghoraya Namah', 'Om, I bow to the non-terrible one — the gentle face of Shiva.', 'vedic_shiva', 'Acceptance', 'OHM ah-GHOH-rah-yah nah-MAH', 'mantra-030.mp3', 'https://paulwagner.com', 'The Aghori path: embracing what we fear →', 'Aghora — "not terrible" — is the south-facing form of Shiva, representing the dissolution of ego and acceptance of all aspects of existence.', 'seed_of_life'),
  (31, 'ॐ वामदेवाय नमः', 'Om Vamadevaya Namah', 'Om, I bow to the beautiful god — the graceful one.', 'vedic_shiva', 'Beauty', 'OHM vah-mah-DAY-vah-yah nah-MAH', 'mantra-031.mp3', 'https://paulwagner.com', 'Beauty as a spiritual path →', 'Vamadeva — "beautiful god" — is the north-facing form of Shiva, representing the creative, nurturing, and beautiful aspects of consciousness.', 'lotus'),
  (32, 'ॐ सद्योजाताय नमः', 'Om Sadyojataya Namah', 'Om, I bow to the instantly born — the creative impulse of consciousness.', 'vedic_shiva', 'Creativity', 'OHM sahd-yoh-JAH-tah-yah nah-MAH', 'mantra-032.mp3', 'https://paulwagner.com', 'Spontaneous creation: how inspiration really works →', 'Sadyojata — "instantly born" — is the west-facing form of Shiva, representing the spontaneous creative power of consciousness.', 'flower_of_life'),
  (33, 'ॐ हरहर महादेव', 'Om Hara Hara Mahadeva', 'Om, remove, remove — O Great God, take away all that binds me.', 'vedic_shiva', 'Liberation', 'OHM HAH-rah HAH-rah mah-hah-DAY-vah', 'mantra-033.mp3', 'https://paulwagner.com', 'What Shiva removes and why you should let him →', 'Hara means "one who removes" — Shiva removes sin, suffering, and the illusion of separation. A powerful mantra of liberation.', 'sri_yantra'),
  (34, 'ॐ शिव शम्भो', 'Om Shiva Shambho', 'Om, Shiva — the self-luminous, the source of joy.', 'vedic_shiva', 'Joy', 'OHM SHIH-vah SHAHM-boh', 'mantra-034.mp3', 'https://paulwagner.com', 'Ananda: the bliss that is your true nature →', 'Shambhu — "self-luminous" or "source of happiness" — is one of Shiva\'s most joyful names. This mantra invokes pure bliss.', 'seed_of_life'),
  (35, 'ॐ नमः शिवाय गुरवे', 'Om Namah Shivaya Gurave', 'Om, I bow to Shiva who is the teacher within.', 'vedic_shiva', 'Learning', 'OHM nah-MAH shih-VAH-yah goo-RAH-vay', 'mantra-035.mp3', 'https://paulwagner.com', 'The inner guru: how Shiva teaches from within →', 'The guru mantra of the Shaiva Siddhanta tradition. Shiva is the first guru — the inner teacher who guides all seekers.', 'lotus'),
  (36, 'ॐ शिवाय गुरवे नमः', 'Om Shivaya Gurave Namah', 'Om, I bow to Shiva the teacher.', 'vedic_shiva', 'Humility', 'OHM shih-VAH-yah goo-RAH-vay nah-MAH', 'mantra-036.mp3', 'https://paulwagner.com', 'The Shiva Sutras: Kashmir Shaivism\'s greatest text →', 'The opening mantra of the Shiva Sutras tradition. Humility before the teacher opens the door to genuine wisdom.', 'seed_of_life'),
  (37, 'ॐ शिवाय नमः शान्तिः', 'Om Shivaya Namah Shantih', 'Om, I bow to Shiva — peace, peace, peace.', 'vedic_shiva', 'Peace', 'OHM shih-VAH-yah nah-MAH SHAHN-tih', 'mantra-037.mp3', 'https://paulwagner.com', 'The three types of suffering and how to end them →', 'The triple shanti at the end of Vedic recitations removes the three types of suffering: physical, mental, and cosmic.', 'lotus'),
  (38, 'ॐ नमः शिवाय स्वाहा', 'Om Namah Shivaya Svaha', 'Om, I bow to Shiva — I offer this into the sacred fire.', 'vedic_shiva', 'Offering', 'OHM nah-MAH shih-VAH-yah svah-HAH', 'mantra-038.mp3', 'https://paulwagner.com', 'Homa: the ancient practice of fire offering →', 'Svaha is the offering call of fire rituals. Adding it transforms any mantra into a complete act of surrender and offering.', 'sri_yantra'),
  (39, 'ॐ शिव ॐ शिव ॐ शिव', 'Om Shiva Om Shiva Om Shiva', 'Om Shiva, Om Shiva, Om Shiva — pure consciousness, again and again.', 'vedic_shiva', 'Absorption', 'OHM SHIH-vah OHM SHIH-vah OHM SHIH-vah', 'mantra-039.mp3', 'https://paulwagner.com', 'The power of divine name repetition →', 'Repetition of the divine name is itself the practice. Three repetitions honor the trimurti and the three states of consciousness.', 'flower_of_life'),
  (40, 'ॐ नमः शिवाय शिवाय नमः ॐ', 'Om Namah Shivaya Shivaya Namah Om', 'Om, I bow to Shiva, to Shiva I bow, Om.', 'vedic_shiva', 'Devotion', 'OHM nah-MAH shih-VAH-yah shih-VAH-yah nah-MAH OHM', 'mantra-040.mp3', 'https://paulwagner.com', 'Non-duality: the teaching that changes everything →', 'A palindromic mantra — it reads the same forward and backward, representing the non-dual nature of Shiva consciousness.', 'seed_of_life'),
  (41, 'ॐ शिवाय विद्महे', 'Om Shivaya Vidmahe', 'Om, may we know Shiva.', 'vedic_shiva', 'Knowledge', 'OHM shih-VAH-yah vid-MAH-hay', 'mantra-041.mp3', 'https://paulwagner.com', 'Direct knowing vs. belief: the Vedantic distinction →', 'The first line of the Shiva Gayatri — a request for direct knowledge of the divine, not merely belief or concept.', 'lotus'),
  (42, 'ॐ शिवाय विद्महे महादेवाय धीमहि', 'Om Shivaya Vidmahe Mahadevaya Dhimahi', 'Om, may we know Shiva, may we meditate on the Great God.', 'vedic_shiva', 'Meditation', 'OHM shih-VAH-yah vid-MAH-hay mah-hah-DAY-vah-yah dhee-MAH-hee', 'mantra-042.mp3', 'https://paulwagner.com', 'The Gayatri structure: the most powerful mantra form →', 'The Shiva Gayatri — a request for illumination through meditation on Shiva\'s supreme nature.', 'sri_yantra'),
  (43, 'तन्नो रुद्रः प्रचोदयात्', 'Tanno Rudrah Prachodayat', 'May Rudra illuminate and inspire us.', 'vedic_shiva', 'Inspiration', 'tahn-NOH ROOD-rah prah-choh-DAH-yaht', 'mantra-043.mp3', 'https://paulwagner.com', 'Prachodayat: the prayer for divine inspiration →', 'The concluding line of the Rudra Gayatri. Prachodayat — "may he inspire" — is the same word used in the Gayatri Mantra.', 'flower_of_life'),
  (44, 'ॐ शिव तत्त्वम् अहम्', 'Om Shiva Tattvam Aham', 'Om, I am the principle of Shiva — pure consciousness.', 'vedic_shiva', 'Self-realization', 'OHM SHIH-vah TAHT-tvahm AH-hahm', 'mantra-044.mp3', 'https://paulwagner.com', 'The mahavakyas: four great sayings of the Upanishads →', 'A mahavakya-style affirmation from Kashmir Shaivism. Tattva means "that-ness" or essential principle. You are not separate from Shiva.', 'sri_yantra'),
  (45, 'ॐ नमः शिवाय नित्यम्', 'Om Namah Shivaya Nityam', 'Om, I bow to Shiva eternally — always and forever.', 'vedic_shiva', 'Commitment', 'OHM nah-MAH shih-VAH-yah NEET-yahm', 'mantra-045.mp3', 'https://paulwagner.com', 'Making a spiritual vow: the power of commitment →', 'Nityam means "eternally" or "always." Adding this word transforms the mantra into a vow of perpetual devotion.', 'seed_of_life'),
  (46, 'ॐ नमो नारायणाय', 'Om Namo Narayanaya', 'Om, I bow to Narayana — the one who dwells in all beings.', 'vedic_vishnu', 'Devotion', 'OHM nah-MOH nah-rah-YAH-nah-yah', 'mantra-046.mp3', 'https://paulwagner.com', 'Narayana: the god who lives inside you →', 'The Ashtakshara — eight-syllable mantra of Vishnu. Narayana means "the one who is the abode of all beings."', 'lotus'),
  (47, 'ॐ नमो भगवते वासुदेवाय', 'Om Namo Bhagavate Vasudevaya', 'Om, I bow to the Lord Vasudeva — the one who pervades all.', 'vedic_vishnu', 'Surrender', 'OHM nah-MOH bhah-gah-VAH-tay vah-soo-DAY-vah-yah', 'mantra-047.mp3', 'https://paulwagner.com', 'The Bhagavata Purana: Vishnu\'s greatest scripture →', 'The Dvadasakshara — twelve-syllable mantra of Vishnu. Vasudeva means "the one who dwells everywhere." From the Bhagavata Purana.', 'lotus'),
  (48, 'हरे कृष्ण हरे कृष्ण', 'Hare Krishna Hare Krishna', 'O Hari, O Krishna — O divine energy, O all-attractive one.', 'vedic_vishnu', 'Joy', 'HAH-ray KRISH-nah HAH-ray KRISH-nah', 'mantra-048.mp3', 'https://paulwagner.com', 'The Maha Mantra: why it works for everyone →', 'The first half of the Maha Mantra. Hare addresses the divine energy (Radha); Krishna means "all-attractive." From the Kali Santarana Upanishad.', 'flower_of_life'),
  (49, 'हरे राम हरे राम', 'Hare Rama Hare Rama', 'O Hari, O Rama — O divine energy, O the one who gives joy.', 'vedic_vishnu', 'Bliss', 'HAH-ray RAH-mah HAH-ray RAH-mah', 'mantra-049.mp3', 'https://paulwagner.com', 'Rama and Krishna: two faces of the same light →', 'The second half of the Maha Mantra. Rama means "the one who gives joy" or "the one in whom the yogis delight."', 'flower_of_life'),
  (50, 'ॐ श्री रामाय नमः', 'Om Shri Ramaya Namah', 'Om, I bow to the radiant Rama — the ideal of righteousness.', 'vedic_vishnu', 'Righteousness', 'OHM shree RAH-mah-yah nah-MAH', 'mantra-050.mp3', 'https://paulwagner.com', 'Dharma: the path of right action →', 'Rama is the seventh avatar of Vishnu and the embodiment of dharma — right action, integrity, and noble character.', 'lotus'),
  (51, 'ॐ श्री कृष्णाय नमः', 'Om Shri Krishnaya Namah', 'Om, I bow to the radiant Krishna — the all-attractive divine.', 'vedic_vishnu', 'Love', 'OHM shree KRISH-nah-yah nah-MAH', 'mantra-051.mp3', 'https://paulwagner.com', 'The Bhagavad Gita in one sentence →', 'Krishna is the eighth avatar of Vishnu and the teacher of the Bhagavad Gita. His name means "all-attractive" or "dark one."', 'lotus'),
  (52, 'ॐ विष्णवे नमः', 'Om Vishnave Namah', 'Om, I bow to Vishnu — the all-pervading one.', 'vedic_vishnu', 'Omnipresence', 'OHM VISH-nah-vay nah-MAH', 'mantra-052.mp3', 'https://paulwagner.com', 'How to feel the divine presence everywhere →', 'Vishnu means "the all-pervading one" — the divine presence that permeates every atom of creation.', 'flower_of_life'),
  (53, 'ॐ नारायणाय विद्महे', 'Om Narayanaya Vidmahe', 'Om, may we know Narayana.', 'vedic_vishnu', 'Knowledge', 'OHM nah-rah-YAH-nah-yah vid-MAH-hay', 'mantra-053.mp3', 'https://paulwagner.com', 'The Vishnu Gayatri: Vaishnava\'s most sacred prayer →', 'The opening of the Vishnu Gayatri — a prayer for direct knowledge of the all-pervading divine presence.', 'lotus'),
  (54, 'ॐ वासुदेवाय धीमहि', 'Om Vasudevaya Dhimahi', 'Om, may we meditate on Vasudeva.', 'vedic_vishnu', 'Meditation', 'OHM vah-soo-DAY-vah-yah dhee-MAH-hee', 'mantra-054.mp3', 'https://paulwagner.com', 'How to meditate on a divine form →', 'The second line of the Vishnu Gayatri. Dhimahi — "may we meditate" — invites sustained contemplation of the divine.', 'lotus'),
  (55, 'तन्नो विष्णुः प्रचोदयात्', 'Tanno Vishnuh Prachodayat', 'May Vishnu illuminate and inspire us.', 'vedic_vishnu', 'Inspiration', 'tahn-NOH VISH-nooh prah-choh-DAH-yaht', 'mantra-055.mp3', 'https://paulwagner.com', 'Vishnu\'s grace: how the preserver works in your life →', 'The concluding line of the Vishnu Gayatri. A prayer for divine illumination in all endeavors.', 'flower_of_life'),
  (56, 'ॐ जय जगदीश हरे', 'Om Jai Jagadish Hare', 'Om, victory to the Lord of the universe who removes all suffering.', 'vedic_vishnu', 'Victory', 'OHM jay jah-gah-DEESH HAH-ray', 'mantra-056.mp3', 'https://paulwagner.com', 'Aarti: the ritual of light and devotion →', 'From the beloved Aarti prayer sung at Vishnu temples across India. Jagadish means "Lord of the world."', 'lotus'),
  (57, 'ॐ श्री विष्णवे नमः', 'Om Shri Vishnave Namah', 'Om, I bow to the radiant, all-pervading Vishnu.', 'vedic_vishnu', 'Abundance', 'OHM shree VISH-nah-vay nah-MAH', 'mantra-057.mp3', 'https://paulwagner.com', 'Lakshmi and Vishnu: the divine couple of abundance →', 'Shri (Lakshmi) is Vishnu\'s consort. Invoking both together brings the fullness of divine grace — both consciousness and abundance.', 'lotus'),
  (58, 'ॐ हरये नमः', 'Om Haraye Namah', 'Om, I bow to Hari — the one who removes all suffering.', 'vedic_vishnu', 'Relief', 'OHM HAH-rah-yay nah-MAH', 'mantra-058.mp3', 'https://paulwagner.com', 'How Vishnu removes suffering: the path of grace →', 'Hari means "the remover" — Vishnu removes the three types of suffering: physical, mental, and karmic.', 'flower_of_life'),
  (59, 'ॐ केशवाय नमः', 'Om Keshavaya Namah', 'Om, I bow to Keshava — the one with beautiful hair.', 'vedic_vishnu', 'Beauty', 'OHM kay-SHAH-vah-yah nah-MAH', 'mantra-059.mp3', 'https://paulwagner.com', 'The 1000 names of Vishnu: the Vishnu Sahasranama →', 'Keshava — "beautiful-haired" or "slayer of Keshi" — is one of Krishna\'s most beloved names. Beauty is a form of the divine.', 'lotus'),
  (60, 'ॐ माधवाय नमः', 'Om Madhavaya Namah', 'Om, I bow to Madhava — the lord of spring, the sweet one.', 'vedic_vishnu', 'Sweetness', 'OHM mah-DHAH-vah-yah nah-MAH', 'mantra-060.mp3', 'https://paulwagner.com', 'Madhurya bhava: the sweetness of divine love →', 'Madhava means "spring" or "sweet" — Krishna as the embodiment of sweetness, beauty, and the joy of creation.', 'lotus'),
  (61, 'ॐ गोविन्दाय नमः', 'Om Govindaya Namah', 'Om, I bow to Govinda — the protector of cows and the earth.', 'vedic_vishnu', 'Protection', 'OHM goh-VIN-dah-yah nah-MAH', 'mantra-061.mp3', 'https://paulwagner.com', 'Vrindavan: the sacred forest of Krishna\'s childhood →', 'Govinda — "protector of cows" — is one of Krishna\'s most beloved names, honoring his childhood as a cowherd in Vrindavan.', 'flower_of_life'),
  (62, 'ॐ विष्णवे नमः त्रिविक्रमाय', 'Om Vishnave Namah Trivikramaya', 'Om, I bow to Vishnu who took three steps to encompass the universe.', 'vedic_vishnu', 'Expansion', 'OHM VISH-nah-vay nah-MAH tree-vik-RAH-mah-yah', 'mantra-062.mp3', 'https://paulwagner.com', 'Vamana: the dwarf who became the universe →', 'Trivikrama — "three steps" — refers to Vamana avatar who measured the entire universe in three strides. Consciousness is boundless.', 'flower_of_life'),
  (63, 'ॐ अच्युताय नमः', 'Om Achyutaya Namah', 'Om, I bow to the infallible one who never falls.', 'vedic_vishnu', 'Steadiness', 'OHM ah-CHYOO-tah-yah nah-MAH', 'mantra-063.mp3', 'https://paulwagner.com', 'Steadiness in the storm: Arjuna\'s lesson →', 'Achyuta — "infallible" or "imperishable" — is one of Krishna\'s names in the Bhagavad Gita. The divine never wavers.', 'lotus'),
  (64, 'ॐ अनन्ताय नमः', 'Om Anantaya Namah', 'Om, I bow to the infinite, endless one.', 'vedic_vishnu', 'Infinity', 'OHM ah-NAHN-tah-yah nah-MAH', 'mantra-064.mp3', 'https://paulwagner.com', 'Ananta Shesha: the serpent of eternity →', 'Ananta — "infinite" — is both a name of Vishnu and the cosmic serpent on which he rests. Infinity is the ground of all existence.', 'flower_of_life'),
  (65, 'ॐ पुण्डरीकाक्षाय नमः', 'Om Pundarikakshaya Namah', 'Om, I bow to the lotus-eyed one.', 'vedic_vishnu', 'Purity', 'OHM poon-dah-ree-KAH-kshah-yah nah-MAH', 'mantra-065.mp3', 'https://paulwagner.com', 'The lotus: growing pure in an impure world →', 'Pundarikaksha — "lotus-eyed" — describes Vishnu\'s eyes as pure as lotus flowers. The lotus grows in mud but remains unstained.', 'lotus'),
  (66, 'ॐ श्रीधराय नमः', 'Om Shridharaya Namah', 'Om, I bow to the one who holds Shri — the divine abundance.', 'vedic_vishnu', 'Abundance', 'OHM shree-DHAH-rah-yah nah-MAH', 'mantra-066.mp3', 'https://paulwagner.com', 'Lakshmi on Vishnu\'s chest: the secret of abundance →', 'Sridhara — "holder of Shri" — honors Vishnu as the one who sustains Lakshmi, the goddess of abundance, on his chest.', 'lotus'),
  (67, 'ॐ हृषीकेशाय नमः', 'Om Hrishikeshaya Namah', 'Om, I bow to the lord of the senses.', 'vedic_vishnu', 'Mastery', 'OHM hrish-ee-KAY-shah-yah nah-MAH', 'mantra-067.mp3', 'https://paulwagner.com', 'Mastery of the senses: the Bhagavad Gita\'s teaching →', 'Hrishikesha — "lord of the senses" — is the name Arjuna uses when asking Krishna to be his charioteer in the Bhagavad Gita.', 'flower_of_life'),
  (68, 'ॐ पद्मनाभाय नमः', 'Om Padmanabhaya Namah', 'Om, I bow to the one with a lotus in his navel — the source of creation.', 'vedic_vishnu', 'Creation', 'OHM pahd-mah-NAH-bhah-yah nah-MAH', 'mantra-068.mp3', 'https://paulwagner.com', 'The cosmic navel: creation from the center →', 'From Vishnu\'s navel grows a lotus, and from that lotus emerges Brahma, the creator. The navel is the center of creative power.', 'lotus'),
  (69, 'ॐ दामोदराय नमः', 'Om Damodaraya Namah', 'Om, I bow to Damodara — the one bound by love.', 'vedic_vishnu', 'Love', 'OHM dah-moh-DAH-rah-yah nah-MAH', 'mantra-069.mp3', 'https://paulwagner.com', 'How love binds even God: the Damodara story →', 'Damodara — "rope around the belly" — refers to Krishna being tied by his mother Yashoda. Love is the only force that can bind the infinite.', 'lotus'),
  (70, 'ॐ सङ्कर्षणाय नमः', 'Om Sankarshanaya Namah', 'Om, I bow to Sankarshana — the one who draws all toward the divine.', 'vedic_vishnu', 'Attraction', 'OHM sahn-kar-SHAH-nah-yah nah-MAH', 'mantra-070.mp3', 'https://paulwagner.com', 'The four vyuhas: Vishnu\'s cosmic emanations →', 'Sankarshana is one of the four vyuha (emanation) forms of Vishnu, representing the attractive power of divine love.', 'flower_of_life'),
  (71, 'ॐ प्रद्युम्नाय नमः', 'Om Pradyumnaya Namah', 'Om, I bow to Pradyumna — the supremely luminous one.', 'vedic_vishnu', 'Radiance', 'OHM prahd-YOOM-nah-yah nah-MAH', 'mantra-071.mp3', 'https://paulwagner.com', 'The luminous mind: how consciousness illuminates →', 'Pradyumna — "supremely luminous" — is the son of Krishna and Rukmini, representing the mind aspect of the divine.', 'lotus'),
  (72, 'ॐ अनिरुद्धाय नमः', 'Om Aniruddhaya Namah', 'Om, I bow to Aniruddha — the unstoppable one.', 'vedic_vishnu', 'Unstoppability', 'OHM ah-nee-ROOD-dhah-yah nah-MAH', 'mantra-072.mp3', 'https://paulwagner.com', 'Your unstoppable nature: removing inner obstacles →', 'Aniruddha — "unstoppable" — represents the ego aspect of the divine that cannot be obstructed. Your true nature cannot be stopped.', 'flower_of_life'),
  (73, 'ॐ पुरुषोत्तमाय नमः', 'Om Purushottamaya Namah', 'Om, I bow to the supreme person — the highest self.', 'vedic_vishnu', 'Excellence', 'OHM poo-roo-SHOH-tah-mah-yah nah-MAH', 'mantra-073.mp3', 'https://paulwagner.com', 'The three purushhas: Gita chapter 15 explained →', 'Purushottama — "supreme person" — is described in the 15th chapter of the Bhagavad Gita as the highest reality beyond both the perishable and imperishable.', 'lotus'),
  (74, 'ॐ विश्वम्भराय नमः', 'Om Vishwambharaya Namah', 'Om, I bow to the one who sustains the entire universe.', 'vedic_vishnu', 'Trust', 'OHM vish-wahm-BHAH-rah-yah nah-MAH', 'mantra-074.mp3', 'https://paulwagner.com', 'Trusting the intelligence that runs the universe →', 'Vishwambhara — "sustainer of the universe" — reminds us that the same intelligence sustaining the cosmos is sustaining you.', 'flower_of_life'),
  (75, 'ॐ जनार्दनाय नमः', 'Om Janardanaya Namah', 'Om, I bow to the one who gives joy to all people.', 'vedic_vishnu', 'Service', 'OHM jah-nahr-DAH-nah-yah nah-MAH', 'mantra-075.mp3', 'https://paulwagner.com', 'Seva: the yoga of selfless service →', 'Janardana — "one who gives joy to people" — is the name used when Krishna acts as the divine servant of humanity.', 'lotus'),
  (76, 'ॐ उपेन्द्राय नमः', 'Om Upendraya Namah', 'Om, I bow to Upendra — the younger brother of Indra.', 'vedic_vishnu', 'Humility', 'OHM oo-PEN-drah-yah nah-MAH', 'mantra-076.mp3', 'https://paulwagner.com', 'The power of appearing small: Vamana\'s teaching →', 'Upendra — "junior Indra" — refers to Vamana avatar. The infinite chose to appear as the smallest, most humble form to teach the greatest lesson.', 'lotus'),
  (77, 'ॐ वामनाय नमः', 'Om Vamanaya Namah', 'Om, I bow to Vamana — the dwarf avatar who measured the cosmos.', 'vedic_vishnu', 'Humility', 'OHM vah-MAH-nah-yah nah-MAH', 'mantra-077.mp3', 'https://paulwagner.com', 'Small appearances, infinite reality →', 'Vamana took three steps to measure earth, sky, and heaven — teaching that the infinite can appear in the smallest form.', 'flower_of_life'),
  (78, 'ॐ श्रीनिवासाय नमः', 'Om Shrinivasaya Namah', 'Om, I bow to Shrinivasa — the abode of Shri (Lakshmi).', 'vedic_vishnu', 'Abundance', 'OHM shree-nih-VAH-sah-yah nah-MAH', 'mantra-078.mp3', 'https://paulwagner.com', 'Tirupati: why 100,000 people visit every day →', 'Shrinivasa — "dwelling place of Shri" — is the name of Vishnu at Tirupati, the most visited temple in the world.', 'lotus'),
  (79, 'ॐ रङ्गनाथाय नमः', 'Om Ranganathaya Namah', 'Om, I bow to Ranganatha — the lord of the stage of creation.', 'vedic_vishnu', 'Presence', 'OHM rahn-gah-NAH-thah-yah nah-MAH', 'mantra-079.mp3', 'https://paulwagner.com', 'Srirangam: the largest functioning temple in the world →', 'Ranganatha — "lord of the stage" — is Vishnu reclining on Ananta at Srirangam. The universe is his stage; we are his players.', 'lotus'),
  (80, 'ॐ वेङ्कटेशाय नमः', 'Om Venkatesaya Namah', 'Om, I bow to Venkatesa — the lord of Venkata hill.', 'vedic_vishnu', 'Grace', 'OHM ven-kah-TAY-shah-yah nah-MAH', 'mantra-080.mp3', 'https://paulwagner.com', 'The seven hills of Tirupati and their meaning →', 'Venkatesa is Vishnu at Tirumala-Tirupati. Venkata means "destroyer of sins." This mantra is believed to grant all desires.', 'lotus'),
  (81, 'ॐ गोपालाय नमः', 'Om Gopalaya Namah', 'Om, I bow to Gopala — the protector of cows and souls.', 'vedic_vishnu', 'Nurturing', 'OHM goh-PAH-lah-yah nah-MAH', 'mantra-081.mp3', 'https://paulwagner.com', 'The cow in Vedic tradition: why she is sacred →', 'Gopala — "protector of cows" — is Krishna as the divine cowherd who tenderly cares for all beings under his protection.', 'flower_of_life'),
  (82, 'ॐ मुकुन्दाय नमः', 'Om Mukundaya Namah', 'Om, I bow to Mukunda — the giver of liberation.', 'vedic_vishnu', 'Liberation', 'OHM moo-KOON-dah-yah nah-MAH', 'mantra-082.mp3', 'https://paulwagner.com', 'Mukti: the four types of liberation in Vedanta →', 'Mukunda — "giver of mukti (liberation)" — is one of Krishna\'s most powerful names. Chanting it is said to dissolve karmic bondage.', 'lotus'),
  (83, 'ॐ मधुसूदनाय नमः', 'Om Madhusudanaya Namah', 'Om, I bow to Madhusudhana — the slayer of the demon Madhu.', 'vedic_vishnu', 'Courage', 'OHM mah-dhoo-SOO-dah-nah-yah nah-MAH', 'mantra-083.mp3', 'https://paulwagner.com', 'The inner demons: what Vishnu really slays →', 'Madhusudhana — "slayer of Madhu" — refers to Vishnu defeating the demon of delusion. This mantra destroys inner demons of doubt and fear.', 'flower_of_life'),
  (84, 'ॐ त्रिविक्रमाय नमः', 'Om Trivikramaya Namah', 'Om, I bow to Trivikrama — the one who strode across the three worlds.', 'vedic_vishnu', 'Expansion', 'OHM tree-vik-RAH-mah-yah nah-MAH', 'mantra-084.mp3', 'https://paulwagner.com', 'The three worlds and how to inhabit them all →', 'Trivikrama\'s three steps represent past, present, and future — or earth, atmosphere, and heaven. Consciousness encompasses all.', 'flower_of_life'),
  (85, 'ॐ वराहाय नमः', 'Om Varahaya Namah', 'Om, I bow to Varaha — the boar avatar who rescued the earth.', 'vedic_vishnu', 'Rescue', 'OHM vah-RAH-hah-yah nah-MAH', 'mantra-085.mp3', 'https://paulwagner.com', 'The Varaha avatar: diving into darkness to save the earth →', 'Varaha lifted the earth from the cosmic ocean on his tusks. This mantra invokes the power to rescue what is precious from darkness.', 'lotus'),
  (86, 'ॐ नृसिंहाय नमः', 'Om Nrisimhaya Namah', 'Om, I bow to Narasimha — the man-lion who protects devotees.', 'vedic_vishnu', 'Protection', 'OHM nree-SIM-hah-yah nah-MAH', 'mantra-086.mp3', 'https://paulwagner.com', 'Prahlada\'s faith: the devotee who couldn\'t be killed →', 'Narasimha burst from a pillar to protect Prahlada — teaching that the divine is present everywhere, in every atom, at every moment.', 'flower_of_life'),
  (87, 'ॐ परशुरामाय नमः', 'Om Parashuramaya Namah', 'Om, I bow to Parashurama — the warrior sage with the axe.', 'vedic_vishnu', 'Justice', 'OHM pah-rah-shoo-RAH-mah-yah nah-MAH', 'mantra-087.mp3', 'https://paulwagner.com', 'When compassion requires fierceness →', 'Parashurama — "Rama with the axe" — is the sixth avatar who restored cosmic justice. Sometimes fierce action is the most compassionate response.', 'lotus'),
  (88, 'ॐ बलराम नमोऽस्तु ते', 'Om Balarama Namostu Te', 'Om, I bow to Balarama — the strong one, Krishna\'s elder brother.', 'vedic_vishnu', 'Strength', 'OHM bah-lah-RAH-mah nah-MOHS-too tay', 'mantra-088.mp3', 'https://paulwagner.com', 'Balarama: the strength behind Krishna\'s play →', 'Balarama — "strong Rama" — is the eighth avatar, representing the strength that supports and protects the divine play of consciousness.', 'flower_of_life'),
  (89, 'ॐ कल्किने नमः', 'Om Kalkine Namah', 'Om, I bow to Kalki — the future avatar who restores righteousness.', 'vedic_vishnu', 'Hope', 'OHM KAHL-kih-nay nah-MAH', 'mantra-089.mp3', 'https://paulwagner.com', 'The Kali Yuga: are we living in the dark age? →', 'Kalki is the tenth and final avatar, yet to come — riding a white horse to restore dharma at the end of the Kali Yuga.', 'lotus'),
  (90, 'ॐ दशावताराय नमः', 'Om Dashavataraaya Namah', 'Om, I bow to the ten avatars — the divine in all its forms.', 'vedic_vishnu', 'Wholeness', 'OHM dah-shah-vah-TAH-rah-yah nah-MAH', 'mantra-090.mp3', 'https://paulwagner.com', 'Darwin and the Dashavatara: evolution in the Vedas →', 'The ten avatars of Vishnu trace the evolution of consciousness from fish to human — a map of spiritual evolution across cosmic time.', 'flower_of_life'),
  (91, 'ॐ ऐं ह्रीं क्लीं', 'Om Aim Hrim Klim', 'Om — the seed of Saraswati, Lakshmi, and Kali — wisdom, abundance, and transformation.', 'vedic_shakti', 'Empowerment', 'OHM AIM hreem kleem', 'mantra-091.mp3', 'https://paulwagner.com', 'The three great goddesses and their bija mantras →', 'Three bija mantras of the divine feminine: Aim (Saraswati/wisdom), Hrim (Lakshmi/heart), Klim (Kali/transformation). Together they invoke the full power of Shakti.', 'sri_yantra'),
  (92, 'ॐ दुर्गायै नमः', 'Om Durgayai Namah', 'Om, I bow to Durga — the invincible one who protects.', 'vedic_shakti', 'Protection', 'OHM door-GAH-yay nah-MAH', 'mantra-092.mp3', 'https://paulwagner.com', 'Durga\'s nine forms: the Navadurga →', 'Durga — "the invincible" or "the one who is difficult to approach" — is the warrior goddess who defeats all forms of evil and ignorance.', 'sri_yantra'),
  (93, 'ॐ काल्यै नमः', 'Om Kalyai Namah', 'Om, I bow to Kali — the dark mother who liberates through transformation.', 'vedic_shakti', 'Transformation', 'OHM KAH-lyay nah-MAH', 'mantra-093.mp3', 'https://paulwagner.com', 'Kali: the goddess who loves you enough to destroy your ego →', 'Kali — "the dark one" or "time" — is the most powerful form of Shakti. She destroys ego and illusion to reveal the eternal self beneath.', 'sri_yantra'),
  (94, 'ॐ श्रीं ह्रीं श्रीं', 'Om Shrim Hrim Shrim', 'Om — Lakshmi\'s seed — the heart — Lakshmi\'s seed again.', 'vedic_shakti', 'Abundance', 'OHM shreem hreem shreem', 'mantra-094.mp3', 'https://paulwagner.com', 'Lakshmi\'s eight forms: the Ashtalakshmi →', 'Shrim is Lakshmi\'s bija — the seed of abundance, beauty, and grace. Hrim is the heart bija. Together they open the heart to receive.', 'lotus'),
  (95, 'ॐ ऐं सरस्वत्यै नमः', 'Om Aim Saraswatyai Namah', 'Om, with the seed of wisdom, I bow to Saraswati.', 'vedic_shakti', 'Wisdom', 'OHM AIM sah-rahs-WAHT-yay nah-MAH', 'mantra-095.mp3', 'https://paulwagner.com', 'Saraswati\'s four arms: the tools of wisdom →', 'Saraswati — "the flowing one" — is the goddess of wisdom, learning, music, and the arts. Aim is her bija, activating the intellect.', 'lotus'),
  (96, 'ॐ श्रीं महालक्ष्म्यै नमः', 'Om Shrim Mahalakshmyai Namah', 'Om, I bow to the great Lakshmi — the goddess of all abundance.', 'vedic_shakti', 'Prosperity', 'OHM shreem mah-hah-LAHK-shmyay nah-MAH', 'mantra-096.mp3', 'https://paulwagner.com', 'The eight forms of Lakshmi and what they offer →', 'Mahalakshmi — "great Lakshmi" — is the supreme form of the goddess of abundance, encompassing all eight forms of wealth.', 'lotus'),
  (97, 'ॐ क्लीं काल्यै नमः', 'Om Klim Kalyai Namah', 'Om, with the seed of transformation, I bow to Kali.', 'vedic_shakti', 'Release', 'OHM kleem KAH-lyay nah-MAH', 'mantra-097.mp3', 'https://paulwagner.com', 'What Kali wants you to release →', 'Klim is the bija of attraction and transformation. Combined with Kali\'s name, it invokes the power to release what no longer serves.', 'sri_yantra'),
  (98, 'ॐ चण्डिकायै नमः', 'Om Chandikayai Namah', 'Om, I bow to Chandika — the fierce, passionate one.', 'vedic_shakti', 'Passion', 'OHM chahn-dee-KAH-yay nah-MAH', 'mantra-098.mp3', 'https://paulwagner.com', 'The Devi Mahatmya: the goddess\'s greatest battle →', 'Chandika is the fierce form of Durga from the Devi Mahatmya. She embodies the passionate, unstoppable force of the divine feminine.', 'sri_yantra'),
  (99, 'ॐ त्रिपुरसुन्दर्यै नमः', 'Om Tripurasundaryai Namah', 'Om, I bow to Tripurasundari — the beauty of the three worlds.', 'vedic_shakti', 'Beauty', 'OHM tree-poo-rah-soon-DAH-ryay nah-MAH', 'mantra-099.mp3', 'https://paulwagner.com', 'Sri Vidya: the highest Shakta tradition →', 'Tripurasundari — "beautiful in the three worlds" — is the supreme goddess of the Sri Vidya tradition, presiding over the Sri Yantra.', 'sri_yantra'),
  (100, 'ॐ भुवनेश्वर्यै नमः', 'Om Bhuvaneshwaryai Namah', 'Om, I bow to Bhuvaneshwari — the queen of the universe.', 'vedic_shakti', 'Sovereignty', 'OHM bhoo-vah-naysh-WAH-ryay nah-MAH', 'mantra-100.mp3', 'https://paulwagner.com', 'The ten Mahavidyas: the wisdom goddesses →', 'Bhuvaneshwari — "queen of the universe" — is the fourth of the ten Mahavidyas, representing the vast space of consciousness.', 'sri_yantra'),
  (101, 'ॐ भैरव्यै नमः', 'Om Bhairavyai Namah', 'Om, I bow to Bhairavi — the fierce, terrifying goddess of liberation.', 'vedic_shakti', 'Fearlessness', 'OHM bhay-RAH-vyay nah-MAH', 'mantra-101.mp3', 'https://paulwagner.com', 'What we fear and why the goddess is not it →', 'Bhairavi — "the terrifying one" — is the fifth Mahavidya. Her terror is only for the ego; to the true self, she is pure love.', 'sri_yantra'),
  (102, 'ॐ छिन्नमस्तायै नमः', 'Om Chhinnamastayai Namah', 'Om, I bow to Chhinnamasta — the self-decapitated goddess of sacrifice.', 'vedic_shakti', 'Sacrifice', 'OHM chhin-nah-MAHS-tah-yay nah-MAH', 'mantra-102.mp3', 'https://paulwagner.com', 'The mystery of Chhinnamasta: love beyond the ego →', 'Chhinnamasta holds her own severed head, feeding her devotees with her blood. She teaches that the highest love is total self-giving.', 'sri_yantra'),
  (103, 'ॐ धूमावत्यै नमः', 'Om Dhumavatyai Namah', 'Om, I bow to Dhumavati — the smoky widow goddess of dissolution.', 'vedic_shakti', 'Acceptance', 'OHM dhoo-mah-VAH-tyay nah-MAH', 'mantra-103.mp3', 'https://paulwagner.com', 'The wisdom of emptiness: Dhumavati\'s gift →', 'Dhumavati — "the smoky one" — represents the void after dissolution. She teaches acceptance of loss, old age, and the wisdom of emptiness.', 'sri_yantra'),
  (104, 'ॐ बगलामुख्यै नमः', 'Om Bagalamukhai Namah', 'Om, I bow to Bagalamukhi — the crane-faced goddess who paralyzes enemies.', 'vedic_shakti', 'Power', 'OHM bah-gah-lah-MOOK-hyay nah-MAH', 'mantra-104.mp3', 'https://paulwagner.com', 'Bagalamukhi: the goddess who silences enemies →', 'Bagalamukhi — "crane-faced" — is the eighth Mahavidya who paralyzes negative forces. She stills the tongue of slander and the mind of confusion.', 'sri_yantra'),
  (105, 'ॐ मातङ्ग्यै नमः', 'Om Matangyai Namah', 'Om, I bow to Matangi — the outcast goddess of inner wisdom.', 'vedic_shakti', 'Authenticity', 'OHM mah-TAHN-gyay nah-MAH', 'mantra-105.mp3', 'https://paulwagner.com', 'Matangi: the wisdom of the outcast →', 'Matangi — the "outcast" or "elephant" goddess — is the ninth Mahavidya, representing wisdom that comes from outside conventional boundaries.', 'lotus'),
  (106, 'ॐ कमलायै नमः', 'Om Kamalayai Namah', 'Om, I bow to Kamala — the lotus goddess, the tantric Lakshmi.', 'vedic_shakti', 'Grace', 'OHM kah-mah-LAH-yay nah-MAH', 'mantra-106.mp3', 'https://paulwagner.com', 'The ten Mahavidyas: a complete map of divine feminine power →', 'Kamala — "lotus" — is the tenth Mahavidya, the tantric form of Lakshmi. She represents the fullness of grace and the beauty of pure consciousness.', 'lotus'),
  (107, 'ॐ तारायै नमः', 'Om Tarayai Namah', 'Om, I bow to Tara — the star goddess who guides across the ocean of existence.', 'vedic_shakti', 'Guidance', 'OHM TAH-rah-yay nah-MAH', 'mantra-107.mp3', 'https://paulwagner.com', 'Tara: the goddess shared by Hinduism and Buddhism →', 'Tara — "star" or "one who saves" — is the second Mahavidya and also a major Buddhist deity. She guides souls across the ocean of samsara.', 'star_of_life'),
  (108, 'ॐ ऐं ह्रीं श्रीं त्रिपुर सुन्दरी', 'Om Aim Hrim Shrim Tripura Sundari', 'Om — wisdom, heart, abundance — beauty of the three worlds.', 'vedic_shakti', 'Completeness', 'OHM AIM hreem shreem tree-POO-rah soon-DAH-ree', 'mantra-108.mp3', 'https://paulwagner.com', 'Why 108 is the most sacred number →', 'Day 108 — the sacred number of the mala. This mantra combines the three great bija mantras with the supreme goddess of the Sri Yantra.', 'sri_yantra'),
  (109, 'ॐ नमो देव्यै महादेव्यै', 'Om Namo Devyai Mahadevyai', 'Om, I bow to the goddess, the great goddess.', 'vedic_shakti', 'Reverence', 'OHM nah-MOH DAY-vyay mah-hah-DAY-vyay', 'mantra-109.mp3', 'https://paulwagner.com', 'The Devi Mahatmya: 700 verses of goddess power →', 'The opening invocation of the Devi Mahatmya — the most sacred text of the Shakta tradition, celebrating the goddess\'s cosmic victory.', 'sri_yantra'),
  (110, 'या देवी सर्वभूतेषु', 'Ya Devi Sarvabhuteshu', 'The goddess who dwells in all beings...', 'vedic_shakti', 'Omnipresence', 'yah DAY-vee sahr-vah-BHOO-tay-shoo', 'mantra-110.mp3', 'https://paulwagner.com', 'The goddess in all forms: the Devi Mahatmya\'s teaching →', 'From the Devi Mahatmya. The full verse continues: "...in the form of consciousness, power, peace, faith, beauty, activity, memory, compassion, and error — I bow to her."', 'flower_of_life'),
  (111, 'नमस्तस्यै नमस्तस्यै नमस्तस्यै नमो नमः', 'Namastasyai Namastasyai Namastasyai Namo Namah', 'I bow to her, I bow to her, I bow to her, I bow.', 'vedic_shakti', 'Surrender', 'nah-mahs-TAHS-yay nah-mahs-TAHS-yay nah-mahs-TAHS-yay nah-MOH nah-MAH', 'mantra-111.mp3', 'https://paulwagner.com', 'The power of triple repetition in mantra →', 'The refrain of the Devi Mahatmya. Triple repetition of surrender to the goddess — a complete act of devotion.', 'sri_yantra'),
  (112, 'ॐ शक्ति शक्ति शक्ति', 'Om Shakti Shakti Shakti', 'Om, power, power, power — the divine feminine energy.', 'vedic_shakti', 'Power', 'OHM SHAHK-tee SHAHK-tee SHAHK-tee', 'mantra-112.mp3', 'https://paulwagner.com', 'Kundalini Shakti: the sleeping serpent power →', 'Shakti is the primordial energy of the universe — the force that animates all of creation. This mantra awakens your own inner Shakti.', 'sri_yantra'),
  (113, 'ॐ जय माँ', 'Om Jai Maa', 'Om, victory to the Divine Mother.', 'vedic_shakti', 'Devotion', 'OHM jay MAH', 'mantra-113.mp3', 'https://paulwagner.com', 'The Divine Mother: the most intimate face of God →', 'The simplest and most heartfelt invocation of the Divine Mother. Maa — "mother" — is the most intimate name for the goddess.', 'lotus'),
  (114, 'ॐ गं गणपतये नमः', 'Om Gam Ganapataye Namah', 'Om, with the seed of Ganesha, I bow to the lord of all beginnings.', 'vedic_ganesha', 'New Beginnings', 'OHM gahm gah-nah-PAH-tah-yay nah-MAH', 'mantra-114.mp3', 'https://paulwagner.com', 'Why Ganesha is invoked first in every ritual →', 'Gam is Ganesha\'s bija mantra. Ganapati — "lord of the ganas" — is invoked at the beginning of every undertaking to remove obstacles.', 'seed_of_life'),
  (115, 'ॐ नमो गणेशाय', 'Om Namo Ganeshaya', 'Om, I bow to Ganesha — the lord of hosts.', 'vedic_ganesha', 'Beginnings', 'OHM nah-MOH gah-NAY-shah-yah', 'mantra-115.mp3', 'https://paulwagner.com', 'Ganesha\'s elephant head: the wisdom of the big picture →', 'Ganesha — "lord of the ganas" — is the remover of obstacles and the bestower of wisdom. He is invoked before all sacred activities.', 'seed_of_life'),
  (116, 'ॐ विघ्नराजाय नमः', 'Om Vighnarajaya Namah', 'Om, I bow to the king of obstacles — who removes all impediments.', 'vedic_ganesha', 'Obstacle Removal', 'OHM vig-nah-RAH-jah-yah nah-MAH', 'mantra-116.mp3', 'https://paulwagner.com', 'Why Ganesha creates obstacles before removing them →', 'Vighnaraja — "king of obstacles" — is Ganesha\'s paradoxical title. He both creates and removes obstacles, teaching that challenges are divine gifts.', 'seed_of_life'),
  (117, 'ॐ एकदन्ताय नमः', 'Om Ekadantaya Namah', 'Om, I bow to the single-tusked one — the one who focuses on the essential.', 'vedic_ganesha', 'Focus', 'OHM ay-kah-DAHN-tah-yah nah-MAH', 'mantra-117.mp3', 'https://paulwagner.com', 'Why Ganesha broke his tusk to write the Mahabharata →', 'Ekadanta — "single tusk" — refers to Ganesha breaking off one tusk to write the Mahabharata. He teaches us to sacrifice the non-essential for the essential.', 'seed_of_life'),
  (118, 'ॐ लम्बोदराय नमः', 'Om Lambodaraya Namah', 'Om, I bow to the large-bellied one who contains all universes.', 'vedic_ganesha', 'Abundance', 'OHM lahm-boh-DAH-rah-yah nah-MAH', 'mantra-118.mp3', 'https://paulwagner.com', 'Ganesha\'s belly: the universe within →', 'Lambodara — "large belly" — represents Ganesha\'s capacity to contain all of existence. His belly holds the entire cosmos.', 'seed_of_life'),
  (119, 'ॐ विनायकाय नमः', 'Om Vinayakaya Namah', 'Om, I bow to Vinayaka — the supreme leader who guides without being led.', 'vedic_ganesha', 'Leadership', 'OHM vih-nah-YAH-kah-yah nah-MAH', 'mantra-119.mp3', 'https://paulwagner.com', 'True leadership: the Vinayaka principle →', 'Vinayaka — "supreme leader" or "one who has no master" — is Ganesha\'s most common name in South India.', 'seed_of_life'),
  (120, 'ॐ गजाननाय नमः', 'Om Gajananaya Namah', 'Om, I bow to the elephant-faced one.', 'vedic_ganesha', 'Wisdom', 'OHM gah-jah-NAH-nah-yah nah-MAH', 'mantra-120.mp3', 'https://paulwagner.com', 'The elephant\'s wisdom: what Ganesha\'s head teaches →', 'Gajanana — "elephant-faced" — honors Ganesha\'s elephant head, which represents wisdom, memory, and the ability to remove obstacles with gentle power.', 'seed_of_life'),
  (121, 'ॐ गणाधिपाय नमः', 'Om Ganadhipaya Namah', 'Om, I bow to the lord of all groups and communities.', 'vedic_ganesha', 'Community', 'OHM gah-nah-dhih-PAH-yah nah-MAH', 'mantra-121.mp3', 'https://paulwagner.com', 'Sangha: the power of spiritual community →', 'Ganadhipa — "lord of groups" — honors Ganesha as the presiding deity of all communities, councils, and collective endeavors.', 'seed_of_life'),
  (122, 'ॐ सिद्धिविनायकाय नमः', 'Om Siddhivinayakaya Namah', 'Om, I bow to Siddhivinayaka — the bestower of all accomplishments.', 'vedic_ganesha', 'Achievement', 'OHM sid-dhih-vih-nah-YAH-kah-yah nah-MAH', 'mantra-122.mp3', 'https://paulwagner.com', 'The eight siddhis: spiritual powers and how to use them →', 'Siddhivinayaka — "bestower of siddhi" — is the most popular form of Ganesha in Mumbai. Siddhi means accomplishment, perfection, and supernatural power.', 'seed_of_life'),
  (123, 'ॐ बुद्धिप्रियाय नमः', 'Om Buddhipriyaya Namah', 'Om, I bow to the one who loves intelligence.', 'vedic_ganesha', 'Intelligence', 'OHM bood-dhih-PRIH-yah-yah nah-MAH', 'mantra-123.mp3', 'https://paulwagner.com', 'Ganesha as the patron of learning: the student\'s mantra →', 'Buddhipriya — "lover of intelligence" — honors Ganesha as the patron of learning, scholarship, and all forms of intellectual endeavor.', 'seed_of_life'),
  (124, 'ॐ विद्याधिपाय नमः', 'Om Vidyadhipaya Namah', 'Om, I bow to the lord of all knowledge.', 'vedic_ganesha', 'Knowledge', 'OHM vid-yah-dhih-PAH-yah nah-MAH', 'mantra-124.mp3', 'https://paulwagner.com', 'Para vidya and apara vidya: two kinds of knowledge →', 'Vidyadhipa — "lord of knowledge" — honors Ganesha as the supreme patron of all forms of learning, from the sacred to the mundane.', 'seed_of_life'),
  (125, 'ॐ मूषकवाहनाय नमः', 'Om Mushakavahanaya Namah', 'Om, I bow to the one whose vehicle is the mouse.', 'vedic_ganesha', 'Humility', 'OHM moo-shah-kah-VAH-hah-nah-yah nah-MAH', 'mantra-125.mp3', 'https://paulwagner.com', 'Why Ganesha rides a mouse: the paradox of power →', 'Ganesha rides a mouse — the smallest of vehicles for the largest of gods. The mouse represents the ego: small, quick, and capable of gnawing through obstacles.', 'seed_of_life'),
  (126, 'ॐ मोदकप्रियाय नमः', 'Om Modakapriyaya Namah', 'Om, I bow to the one who loves modaka — the sweet of bliss.', 'vedic_ganesha', 'Sweetness', 'OHM moh-dah-kah-PRIH-yah-yah nah-MAH', 'mantra-126.mp3', 'https://paulwagner.com', 'Offering to Ganesha: the art of sacred giving →', 'Modaka — a sweet rice dumpling — is Ganesha\'s favorite offering. It represents the sweetness of spiritual realization.', 'seed_of_life'),
  (127, 'ॐ हेरम्बाय नमः', 'Om Herambaya Namah', 'Om, I bow to Heramba — the protector of the weak.', 'vedic_ganesha', 'Protection', 'OHM hay-RAHM-bah-yah nah-MAH', 'mantra-127.mp3', 'https://paulwagner.com', 'Heramba: Ganesha\'s fierce protective form →', 'Heramba — "protector of the weak" — is a five-headed form of Ganesha who specifically protects those who are vulnerable or in difficulty.', 'seed_of_life'),
  (128, 'ॐ महागणपतये नमः', 'Om Mahaganapataye Namah', 'Om, I bow to the great lord of all hosts.', 'vedic_ganesha', 'Greatness', 'OHM mah-hah-gah-nah-PAH-tah-yay nah-MAH', 'mantra-128.mp3', 'https://paulwagner.com', 'The 32 forms of Ganesha: a complete guide →', 'Mahaganapataye — "great Ganapati" — is the supreme form of Ganesha, combining all his powers and aspects into one.', 'seed_of_life'),
  (129, 'ॐ गणेशाय विद्महे', 'Om Ganeshaya Vidmahe', 'Om, may we know Ganesha.', 'vedic_ganesha', 'Knowledge', 'OHM gah-NAY-shah-yah vid-MAH-hay', 'mantra-129.mp3', 'https://paulwagner.com', 'The Ganesha Gayatri: the most powerful Ganesha mantra →', 'The opening of the Ganesha Gayatri — a prayer for direct knowledge of the remover of obstacles.', 'seed_of_life'),
  (130, 'ॐ वक्रतुण्डाय धीमहि', 'Om Vakratundaya Dhimahi', 'Om, may we meditate on the curved-trunk one.', 'vedic_ganesha', 'Meditation', 'OHM vahk-rah-TOON-dah-yah dhee-MAH-hee', 'mantra-130.mp3', 'https://paulwagner.com', 'Ganesha\'s trunk: the power of discernment →', 'Vakratunda — "curved trunk" — honors Ganesha\'s trunk, which curves to pick up the sweetness of life. The second line of the Ganesha Gayatri.', 'seed_of_life'),
  (131, 'तन्नो दन्तिः प्रचोदयात्', 'Tanno Dantih Prachodayat', 'May the tusked one inspire and illuminate us.', 'vedic_ganesha', 'Inspiration', 'tahn-NOH DAHN-tih prah-choh-DAH-yaht', 'mantra-131.mp3', 'https://paulwagner.com', 'The Mahabharata: the world\'s longest poem →', 'The concluding line of the Ganesha Gayatri. Danti — "tusked one" — refers to Ganesha\'s single tusk, the pen that wrote the Mahabharata.', 'seed_of_life'),
  (132, 'वक्रतुण्ड महाकाय', 'Vakratunda Mahakaya', 'O curved-trunk one, O great-bodied one...', 'vedic_ganesha', 'Blessings', 'vahk-rah-TOON-dah mah-hah-KAH-yah', 'mantra-132.mp3', 'https://paulwagner.com', 'The Vakratunda shloka: Ganesha\'s most popular prayer →', 'The opening of the most popular Ganesha shloka. The full verse: "O curved-trunk, great-bodied, brilliant as a million suns — remove all obstacles from my work, always."', 'seed_of_life'),
  (133, 'सूर्यकोटि समप्रभ', 'Suryakoti Samaprabha', 'Brilliant as ten million suns.', 'vedic_ganesha', 'Radiance', 'soor-yah-KOH-tee sah-mah-PRAH-bhah', 'mantra-133.mp3', 'https://paulwagner.com', 'The light of consciousness: what Ganesha\'s radiance means →', 'The second line of the Vakratunda shloka. Ganesha\'s radiance is compared to ten million suns — the light of consciousness itself.', 'seed_of_life'),
  (134, 'निर्विघ्नं कुरु मे देव', 'Nirvighnam Kuru Me Deva', 'O God, make my work free from obstacles.', 'vedic_ganesha', 'Success', 'neer-VIG-nahm KOO-roo may DAY-vah', 'mantra-134.mp3', 'https://paulwagner.com', 'Removing obstacles: the Ganesha principle in action →', 'The third line of the Vakratunda shloka — a direct prayer for obstacle-free action. Nirvighna means "without obstacles."', 'seed_of_life'),
  (135, 'सर्वकार्येषु सर्वदा', 'Sarvakaryeshu Sarvada', 'In all endeavors, always.', 'vedic_ganesha', 'Constancy', 'sahr-vah-KAH-ryay-shoo sahr-VAH-dah', 'mantra-135.mp3', 'https://paulwagner.com', 'Living in constant prayer: the practice of remembrance →', 'The final line of the Vakratunda shloka. Sarvada — "always" — transforms the prayer into a constant, living invocation.', 'seed_of_life'),
  (136, 'ॐ गं ॐ गं ॐ गं', 'Om Gam Om Gam Om Gam', 'Om, Ganesha\'s seed — three times — opening all doors.', 'vedic_ganesha', 'Opening', 'OHM gahm OHM gahm OHM gahm', 'mantra-136.mp3', 'https://paulwagner.com', 'The root chakra and Ganesha: the foundation of practice →', 'The simplest Ganesha practice: just his bija, three times. Gam activates the root chakra and opens the path ahead.', 'seed_of_life'),
  (137, 'ॐ भूर्भुवः स्वः', 'Om Bhur Bhuvah Svah', 'Om — the physical world, the vital world, the celestial world.', 'vedic_solar', 'Wholeness', 'OHM bhoor BHOO-vah svah', 'mantra-137.mp3', 'https://paulwagner.com', 'The three worlds of the Gayatri: a map of consciousness →', 'The Vyahritis — three sacred utterances that open the Gayatri Mantra. They represent the three planes of existence and the three states of consciousness.', 'sri_yantra'),
  (138, 'तत् सवितुर् वरेण्यम्', 'Tat Savitur Varenyam', 'That divine solar radiance which is most adorable.', 'vedic_solar', 'Reverence', 'taht sah-VEE-toor vah-REN-yahm', 'mantra-138.mp3', 'https://paulwagner.com', 'Savitri: the solar deity behind the Gayatri →', 'The second line of the Gayatri Mantra. Savitri is the solar deity — the divine light that illuminates both the outer sun and the inner light of consciousness.', 'sri_yantra'),
  (139, 'भर्गो देवस्य धीमहि', 'Bhargo Devasya Dhimahi', 'May we meditate on the divine radiance.', 'vedic_solar', 'Meditation', 'BHAHR-goh DAY-vahs-yah dhee-MAH-hee', 'mantra-139.mp3', 'https://paulwagner.com', 'Bhargo: the light that destroys darkness →', 'The third line of the Gayatri. Bhargo means "radiance" or "splendor" — the light that burns away ignorance.', 'sri_yantra'),
  (140, 'धियो यो नः प्रचोदयात्', 'Dhiyo Yo Nah Prachodayat', 'May that divine light inspire and illuminate our intellect.', 'vedic_solar', 'Illumination', 'DHEE-yoh yoh nah prah-choh-DAH-yaht', 'mantra-140.mp3', 'https://paulwagner.com', 'The Gayatri Mantra: the most powerful mantra in the Vedas →', 'The final line of the Gayatri Mantra. Dhiyo — "intellect" — is what we offer to the divine light for purification and illumination.', 'sri_yantra'),
  (141, 'ॐ भूर्भुवः स्वः तत् सवितुर् वरेण्यम् भर्गो देवस्य धीमहि धियो यो नः प्रचोदयात्', 'Om Bhur Bhuvah Svah Tat Savitur Varenyam Bhargo Devasya Dhimahi Dhiyo Yo Nah Prachodayat', 'Om — the three worlds — that divine solar radiance which is most adorable — may we meditate on it — may it inspire our intellect.', 'vedic_solar', 'Complete Practice', 'OHM bhoor BHOO-vah svah taht sah-VEE-toor vah-REN-yahm BHAHR-goh DAY-vahs-yah dhee-MAH-hee DHEE-yoh yoh nah prah-choh-DAH-yaht', 'mantra-141.mp3', 'https://paulwagner.com', 'Chanting the Gayatri at sunrise: the complete practice →', 'The complete Gayatri Mantra — the most sacred mantra of the Vedic tradition, chanted at sunrise and sunset for thousands of years.', 'sri_yantra'),
  (142, 'ॐ सूर्याय नमः', 'Om Suryaya Namah', 'Om, I bow to Surya — the solar deity, the source of all light.', 'vedic_solar', 'Vitality', 'OHM SOOR-yah-yah nah-MAH', 'mantra-142.mp3', 'https://paulwagner.com', 'Surya Namaskar: the sun salutation as prayer →', 'Surya is the solar deity — the visible form of the divine. The sun is the source of all life on earth and a symbol of the inner light of consciousness.', 'flower_of_life'),
  (143, 'ॐ आदित्याय नमः', 'Om Adityaya Namah', 'Om, I bow to Aditya — the son of Aditi, the infinite.', 'vedic_solar', 'Infinity', 'OHM ah-DIT-yah-yah nah-MAH', 'mantra-143.mp3', 'https://paulwagner.com', 'Aditi: the infinite mother of the gods →', 'Aditya — "son of Aditi" — is the sun as the child of the infinite. Aditi means "the boundless" — the cosmic mother of all the gods.', 'flower_of_life'),
  (144, 'ॐ मित्राय नमः', 'Om Mitraya Namah', 'Om, I bow to Mitra — the sun as the universal friend.', 'vedic_solar', 'Friendship', 'OHM MEET-rah-yah nah-MAH', 'mantra-144.mp3', 'https://paulwagner.com', 'Mitra: the sun as the friend of all beings →', 'Mitra — "friend" — is the sun as the universal benefactor. The sun shines equally on all without discrimination.', 'flower_of_life'),
  (145, 'ॐ रवये नमः', 'Om Ravaye Namah', 'Om, I bow to Ravi — the radiant one.', 'vedic_solar', 'Radiance', 'OHM RAH-vah-yay nah-MAH', 'mantra-145.mp3', 'https://paulwagner.com', 'The 12 names of the sun: the Surya Namaskar mantras →', 'Ravi — "the radiant" — is one of the twelve names of the sun recited during Surya Namaskar. Radiance is the sun\'s essential nature.', 'flower_of_life'),
  (146, 'ॐ सूर्याय नमः भास्कराय नमः', 'Om Suryaya Namah Bhaskaraya Namah', 'Om, I bow to Surya, I bow to Bhaskara — the one who illuminates.', 'vedic_solar', 'Clarity', 'OHM SOOR-yah-yah nah-MAH BHAHS-kah-rah-yah nah-MAH', 'mantra-146.mp3', 'https://paulwagner.com', 'Light as a metaphor for consciousness →', 'Bhaskara — "the illuminator" — is the sun as the force that makes all things visible and knowable.', 'flower_of_life'),
  (147, 'ॐ खगाय नमः', 'Om Khagaya Namah', 'Om, I bow to Khaga — the one who moves through the sky.', 'vedic_solar', 'Freedom', 'OHM khah-GAH-yah nah-MAH', 'mantra-147.mp3', 'https://paulwagner.com', 'The sun\'s daily journey: a meditation on freedom →', 'Khaga — "sky-mover" — honors the sun\'s daily journey across the heavens. The sun\'s freedom of movement is a symbol of liberated consciousness.', 'flower_of_life'),
  (148, 'ॐ पूष्णे नमः', 'Om Pushne Namah', 'Om, I bow to Pushan — the nourisher of all.', 'vedic_solar', 'Nourishment', 'OHM POOSH-nay nah-MAH', 'mantra-148.mp3', 'https://paulwagner.com', 'Pushan: the sun as the cosmic nourisher →', 'Pushan — "the nourisher" — is the sun as the source of all food and sustenance. The sun nourishes every living being without exception.', 'flower_of_life'),
  (149, 'ॐ हिरण्यगर्भाय नमः', 'Om Hiranyagarbhaya Namah', 'Om, I bow to Hiranyagarbha — the golden womb of creation.', 'vedic_solar', 'Creation', 'OHM hih-rahn-yah-GAHR-bhah-yah nah-MAH', 'mantra-149.mp3', 'https://paulwagner.com', 'Hiranyagarbha: the golden egg of creation →', 'Hiranyagarbha — "golden womb" — is the cosmic egg from which the universe was born. The sun is its visible manifestation.', 'flower_of_life'),
  (150, 'ॐ मरीचये नमः', 'Om Marichaye Namah', 'Om, I bow to Marichi — the ray of light.', 'vedic_solar', 'Subtlety', 'OHM mah-REE-chah-yay nah-MAH', 'mantra-150.mp3', 'https://paulwagner.com', 'The ray and the sun: the relationship between soul and God →', 'Marichi — "ray of light" — honors the individual rays of the sun. Each ray is both part of the sun and distinct from it — like each soul in relation to the divine.', 'flower_of_life'),
  (151, 'ॐ आदित्याय सवित्रे नमः', 'Om Adityaya Savitre Namah', 'Om, I bow to Aditya-Savitri — the solar deity who animates all life.', 'vedic_solar', 'Animation', 'OHM ah-DIT-yah-yah sah-VIT-ray nah-MAH', 'mantra-151.mp3', 'https://paulwagner.com', 'Prana: the solar life force within you →', 'Savitri — "the animating one" — is the sun as the force that animates all living beings. Without the sun, there is no life.', 'flower_of_life'),
  (152, 'ॐ दिवाकराय नमः', 'Om Divakaraya Namah', 'Om, I bow to Divakara — the maker of the day.', 'vedic_solar', 'New Day', 'OHM dee-vah-KAH-rah-yah nah-MAH', 'mantra-152.mp3', 'https://paulwagner.com', 'The gift of each new day: a morning practice →', 'Divakara — "day-maker" — honors the sun as the creator of each new day. Every sunrise is a new beginning, a fresh opportunity.', 'flower_of_life'),
  (153, 'ॐ प्रभाकराय नमः', 'Om Prabhakaraya Namah', 'Om, I bow to Prabhakara — the maker of light.', 'vedic_solar', 'Enlightenment', 'OHM prah-bhah-KAH-rah-yah nah-MAH', 'mantra-153.mp3', 'https://paulwagner.com', 'Enlightenment: what it really means →', 'Prabhakara — "maker of light" — honors the sun as the source of all illumination, both physical and spiritual.', 'flower_of_life'),
  (154, 'ॐ विवस्वते नमः', 'Om Vivasvate Namah', 'Om, I bow to Vivasvat — the brilliant, shining one.', 'vedic_solar', 'Brilliance', 'OHM vih-VAHS-vah-tay nah-MAH', 'mantra-154.mp3', 'https://paulwagner.com', 'The eternal yoga: Krishna\'s teaching to the sun →', 'Vivasvat — "the brilliant" — is the Vedic name of the sun. In the Bhagavad Gita, Krishna says he first taught this yoga to Vivasvat.', 'flower_of_life'),
  (155, 'ॐ सवित्रे नमः', 'Om Savitre Namah', 'Om, I bow to Savitri — the solar deity of the Gayatri.', 'vedic_solar', 'Inspiration', 'OHM sah-VIT-ray nah-MAH', 'mantra-155.mp3', 'https://paulwagner.com', 'Savitri: the goddess behind the Gayatri Mantra →', 'Savitri is the specific solar deity invoked in the Gayatri Mantra. The name means "one who inspires" or "one who animates."', 'sri_yantra'),
  (156, 'ॐ आर्काय नमः', 'Om Arkaya Namah', 'Om, I bow to Arka — the sun as the worthy of praise.', 'vedic_solar', 'Gratitude', 'OHM AHR-kah-yah nah-MAH', 'mantra-156.mp3', 'https://paulwagner.com', 'Gratitude as a spiritual practice →', 'Arka — "worthy of praise" — honors the sun as the most visible and constant blessing in our lives. Gratitude for the sun is gratitude for life itself.', 'flower_of_life'),
  (157, 'ॐ भानवे नमः', 'Om Bhanave Namah', 'Om, I bow to Bhanu — the luminous one.', 'vedic_solar', 'Luminosity', 'OHM BHAH-nah-vay nah-MAH', 'mantra-157.mp3', 'https://paulwagner.com', 'Your natural luminosity: the practice of shining →', 'Bhanu — "luminous" — is one of the twelve names of the sun. Luminosity is the sun\'s nature; it cannot help but shine.', 'flower_of_life'),
  (158, 'ॐ इन्द्राय नमः', 'Om Indraya Namah', 'Om, I bow to Indra — the king of the gods, lord of lightning.', 'vedic_solar', 'Power', 'OHM IN-drah-yah nah-MAH', 'mantra-158.mp3', 'https://paulwagner.com', 'Indra and the thunderbolt: the power of awakening →', 'Indra is the king of the Vedic gods, wielder of the thunderbolt (vajra). He represents the power of the awakened mind.', 'flower_of_life'),
  (159, 'ॐ वरुणाय नमः', 'Om Varunaya Namah', 'Om, I bow to Varuna — the lord of cosmic order and the waters.', 'vedic_solar', 'Order', 'OHM vah-ROO-nah-yah nah-MAH', 'mantra-159.mp3', 'https://paulwagner.com', 'Rita: the cosmic order that underlies all existence →', 'Varuna is the Vedic god of cosmic order (rita) and the waters. He sees all actions and maintains the moral order of the universe.', 'flower_of_life'),
  (160, 'ॐ अग्नये नमः', 'Om Agnaye Namah', 'Om, I bow to Agni — the sacred fire, the divine messenger.', 'vedic_solar', 'Purification', 'OHM AHG-nah-yay nah-MAH', 'mantra-160.mp3', 'https://paulwagner.com', 'Agni: the first word of the Vedas →', 'Agni is the first word of the Rigveda. The sacred fire is the divine messenger between humans and gods, and the purifier of all offerings.', 'flower_of_life'),
  (161, 'ॐ वायवे नमः', 'Om Vayave Namah', 'Om, I bow to Vayu — the wind, the breath of life.', 'vedic_solar', 'Breath', 'OHM VAH-yah-vay nah-MAH', 'mantra-161.mp3', 'https://paulwagner.com', 'Pranayama: the yoga of the breath →', 'Vayu — "wind" or "breath" — is the Vedic god of air and prana. The breath is the most direct link between the physical and spiritual.', 'flower_of_life'),
  (162, 'ॐ पृथिव्यै नमः', 'Om Prithivyai Namah', 'Om, I bow to Prithivi — the earth, our mother.', 'vedic_solar', 'Grounding', 'OHM prih-THIV-yay nah-MAH', 'mantra-162.mp3', 'https://paulwagner.com', 'Prithivi: the earth as the divine mother →', 'Prithivi — "the broad one" — is the Vedic earth goddess. The earth supports all life without discrimination. Grounding is the foundation of all practice.', 'lotus'),
  (163, 'ॐ आपः शान्तिः', 'Om Apah Shantih', 'Om, may the waters bring peace.', 'vedic_solar', 'Peace', 'OHM AH-pah SHAHN-tih', 'mantra-163.mp3', 'https://paulwagner.com', 'The Shanti Patha: the Vedic prayer for universal peace →', 'From the Shanti Patha — the Vedic peace invocation. The waters (apah) represent the flow of life and the cleansing power of grace.', 'lotus'),
  (164, 'ॐ ओषधयः शान्तिः', 'Om Oshadhayah Shantih', 'Om, may the herbs and plants bring peace.', 'vedic_solar', 'Healing', 'OHM oh-shah-DHAH-yah SHAHN-tih', 'mantra-164.mp3', 'https://paulwagner.com', 'Ayurveda: the Vedic science of healing →', 'From the Shanti Patha. The healing plants of the earth are invoked for peace — honoring the medicinal wisdom of the natural world.', 'lotus'),
  (165, 'ॐ विश्वानि देव सवितर्', 'Om Vishwani Deva Savitar', 'O divine Savitri, remove all that is harmful from us.', 'vedic_solar', 'Purification', 'OHM vish-WAH-nih DAY-vah sah-VEE-tahr', 'mantra-165.mp3', 'https://paulwagner.com', 'The Yajurveda: the Veda of ritual action →', 'From the Yajurveda. A prayer to the solar deity to remove all that is harmful and bring only what is beneficial.', 'sri_yantra'),
  (166, 'दुरितानि परासुव', 'Duritani Parasuva', 'Remove all our sins and shortcomings.', 'vedic_solar', 'Forgiveness', 'doo-rih-TAH-nih pah-rah-SOO-vah', 'mantra-166.mp3', 'https://paulwagner.com', 'Forgiveness as a spiritual practice →', 'The second line of the Vishwani prayer. Duritani means "that which causes pain" — the prayer asks for removal of all inner obstacles.', 'sri_yantra'),
  (167, 'यद् भद्रं तन्न आसुव', 'Yad Bhadram Tanna Asuva', 'And bring to us all that is auspicious.', 'vedic_solar', 'Auspiciousness', 'yahd BHAHD-rahm tahn-NAH ah-SOO-vah', 'mantra-167.mp3', 'https://paulwagner.com', 'Bhadram: the Vedic vision of the good life →', 'The final line of the Vishwani prayer. Bhadram — "auspicious" — is the Vedic word for all that is good, beautiful, and beneficial.', 'sri_yantra'),
  (168, 'ॐ सूर्य नमस्कार', 'Om Surya Namaskar', 'Om, salutation to the sun.', 'vedic_solar', 'Gratitude', 'OHM SOOR-yah nah-mahs-KAHR', 'mantra-168.mp3', 'https://paulwagner.com', 'The complete Surya Namaskar practice →', 'Surya Namaskar — "sun salutation" — is both a physical yoga practice and a devotional act. Each movement is accompanied by a mantra to the sun.', 'flower_of_life'),
  (169, 'ॐ ह्रां ह्रीं ह्रौं सः सूर्याय नमः', 'Om Hram Hrim Hraum Sah Suryaya Namah', 'Om — the three solar bija mantras — I am that — I bow to Surya.', 'vedic_solar', 'Solar Power', 'OHM hrahm hreem hrowm sah SOOR-yah-yah nah-MAH', 'mantra-169.mp3', 'https://paulwagner.com', 'Solar bija mantras: seeds of solar power →', 'The complete solar bija mantra. Hram, Hrim, Hraum are the three seed syllables of the sun, representing its three aspects: rising, noon, and setting.', 'sri_yantra'),
  (170, 'ॐ जपाकुसुमसङ्काशम्', 'Om Japaakusumasankasham', 'Om, the one who resembles the hibiscus flower.', 'vedic_solar', 'Beauty', 'OHM jah-pah-koo-soo-mah-sahn-KAH-shahm', 'mantra-170.mp3', 'https://paulwagner.com', 'The Aditya Hridayam: the heart of the sun →', 'The opening of the Aditya Hridayam — the solar hymn from the Ramayana. The sun is compared to the red hibiscus flower at dawn.', 'flower_of_life'),
  (171, 'काश्यपेयं महाद्युतिम्', 'Kashyapeyam Mahadyutim', 'The son of Kashyapa, of great radiance.', 'vedic_solar', 'Lineage', 'KAHSH-yah-pay-yahm mah-hah-DYOO-tihm', 'mantra-171.mp3', 'https://paulwagner.com', 'Kashyapa: the progenitor of all life →', 'The second line of the Aditya Hridayam. The sun is the son of the sage Kashyapa — reminding us that even the sun has a lineage and a teacher.', 'flower_of_life'),
  (172, 'तमोऽरिं सर्वपापघ्नम्', 'Tamoriṃ Sarvapapagnam', 'The enemy of darkness, the destroyer of all sins.', 'vedic_solar', 'Liberation', 'tah-MOH-rim sahr-vah-PAH-pahg-nahm', 'mantra-172.mp3', 'https://paulwagner.com', 'The Aditya Hridayam: how Rama defeated Ravana →', 'The third line of the Aditya Hridayam. The sun destroys both physical darkness and the inner darkness of ignorance and sin.', 'sri_yantra'),
  (173, 'प्रणतोऽस्मि दिवाकरम्', 'Pranato\'smi Divakaram', 'I bow to the maker of the day.', 'vedic_solar', 'Humility', 'prah-NAH-tohs-mih dee-vah-KAH-rahm', 'mantra-173.mp3', 'https://paulwagner.com', 'Pranama: the practice of sacred bowing →', 'The final line of the Aditya Hridayam opening verse. Pranata — "bowing" — is the posture of humility before the divine light.', 'flower_of_life'),
  (174, 'ॐ नमः सूर्याय शान्ताय', 'Om Namah Suryaya Shantaya', 'Om, I bow to the peaceful sun.', 'vedic_solar', 'Equanimity', 'OHM nah-MAH SOOR-yah-yah SHAHN-tah-yah', 'mantra-174.mp3', 'https://paulwagner.com', 'Equanimity: the sun\'s greatest teaching →', 'The sun is peaceful — it shines without effort, without preference, without agitation. This mantra invokes solar equanimity.', 'flower_of_life'),
  (175, 'ॐ नमः सूर्याय सर्वदाय', 'Om Namah Suryaya Sarvadaya', 'Om, I bow to the sun who gives everything.', 'vedic_solar', 'Generosity', 'OHM nah-MAH SOOR-yah-yah sahr-VAH-dah-yah', 'mantra-175.mp3', 'https://paulwagner.com', 'The sun\'s generosity: giving without expectation →', 'The sun gives its light freely to all — the saint and the sinner, the rich and the poor. This mantra invokes divine generosity.', 'flower_of_life'),
  (176, 'ॐ सूर्य देव नमोऽस्तु ते', 'Om Surya Deva Namostu Te', 'Om, I bow to you, O solar deity.', 'vedic_solar', 'Reverence', 'OHM SOOR-yah DAY-vah nah-MOHS-too tay', 'mantra-176.mp3', 'https://paulwagner.com', 'Daily sun practice: the simplest solar sadhana →', 'A simple, direct salutation to the sun. Namostu — "may there be bowing" — expresses perpetual reverence.', 'flower_of_life'),
  (177, 'ॐ प्रसीद प्रसीद प्रभो', 'Om Prasida Prasida Prabho', 'Om, be pleased, be pleased, O Lord.', 'vedic_solar', 'Grace', 'OHM prah-SEE-dah prah-SEE-dah PRAH-bhoh', 'mantra-177.mp3', 'https://paulwagner.com', 'Prasada: the grace that flows from the divine →', 'Prasida — "be pleased" or "be gracious" — is a prayer for divine grace. The triple repetition intensifies the request.', 'flower_of_life'),
  (178, 'ॐ सर्वदेवनमस्कारः', 'Om Sarvadevanamaskarah', 'Om, salutation to all the gods.', 'vedic_solar', 'Inclusivity', 'OHM sahr-vah-DAY-vah-nah-mahs-KAH-rah', 'mantra-178.mp3', 'https://paulwagner.com', 'Ekam sat vipra bahudha vadanti: one truth, many names →', 'A universal salutation to all divine forms. The Vedas teach that all gods are aspects of the one divine reality.', 'flower_of_life'),
  (179, 'केशवं प्रति गच्छति', 'Keshavam Prati Gacchati', 'Reaches Keshava (the supreme).', 'vedic_solar', 'Unity', 'KAY-shah-vahm PRAH-tih GAHCH-chah-tih', 'mantra-179.mp3', 'https://paulwagner.com', 'All paths lead to the same peak →', 'The second line of the universal salutation verse: "Salutation to all gods reaches the supreme." All paths lead to the same destination.', 'flower_of_life'),
  (180, 'ॐ तेजोऽसि तेजो मयि धेहि', 'Om Tejo\'si Tejo Mayi Dhehi', 'Om, you are radiance — place that radiance in me.', 'vedic_solar', 'Empowerment', 'OHM tay-JOH-see tay-JOH mah-YEE DHAY-hee', 'mantra-180.mp3', 'https://paulwagner.com', 'Tejas: the inner radiance of the awakened person →', 'From the Yajurveda. A prayer to receive the sun\'s radiance — not just its physical light, but its inner quality of brilliance and clarity.', 'sri_yantra'),
  (181, 'ॐ वीर्यमसि वीर्यं मयि धेहि', 'Om Viryamasi Viryam Mayi Dhehi', 'Om, you are vitality — place that vitality in me.', 'vedic_solar', 'Vitality', 'OHM veer-YAHM-ah-see veer-YAHM mah-YEE DHAY-hee', 'mantra-181.mp3', 'https://paulwagner.com', 'Virya: the heroic energy of the spiritual warrior →', 'From the Yajurveda. Virya — "vitality" or "heroic energy" — is the solar quality of dynamic, purposeful action.', 'flower_of_life'),
  (182, 'ॐ बलमसि बलं मयि धेहि', 'Om Balamasi Balam Mayi Dhehi', 'Om, you are strength — place that strength in me.', 'vedic_solar', 'Strength', 'OHM bah-LAHM-ah-see bah-LAHM mah-YEE DHAY-hee', 'mantra-182.mp3', 'https://paulwagner.com', 'Bala: the strength that comes from practice →', 'From the Yajurveda. Bala — "strength" — is the solar quality of physical and spiritual fortitude. The sun never wavers; neither should we.', 'flower_of_life'),
  (183, 'ॐ मणि पद्मे हूँ', 'Om Mani Padme Hum', 'Om — the jewel in the lotus — hum.', 'buddhist', 'Compassion', 'OHM mah-NEE pahd-MAY hoom', 'mantra-183.mp3', 'https://paulwagner.com', 'Om Mani Padme Hum: the six syllables of compassion →', 'The mantra of Avalokiteshvara — the bodhisattva of compassion. The most widely chanted mantra in the world. The jewel is the awakened mind; the lotus is the world.', 'lotus'),
  (184, 'ॐ तारे तुत्तारे तुरे स्वाहा', 'Om Tare Tuttare Ture Svaha', 'Om — Tara who liberates — Tara who liberates swiftly — Tara who protects — so be it.', 'buddhist', 'Liberation', 'OHM TAH-ray too-TAH-ray TOO-ray svah-HAH', 'mantra-184.mp3', 'https://paulwagner.com', 'Green Tara: the swift liberator →', 'The mantra of Green Tara — the swift-acting bodhisattva who saves from the eight fears. Tare means "she who liberates."', 'lotus'),
  (185, 'ॐ अमिताभ हृदय', 'Om Amitabha Hridaya', 'Om — the heart of Amitabha — the buddha of infinite light.', 'buddhist', 'Light', 'OHM ah-mee-TAH-bhah hrih-DAH-yah', 'mantra-185.mp3', 'https://paulwagner.com', 'Amitabha Buddha: the pure land of infinite light →', 'Amitabha — "infinite light" — is the buddha of the western pure land. His light reaches all beings without exception.', 'lotus'),
  (186, 'नमो अमिताभाय', 'Namo Amitabhaya', 'I take refuge in Amitabha — the buddha of infinite light.', 'buddhist', 'Refuge', 'nah-MOH ah-mee-TAH-bhah-yah', 'mantra-186.mp3', 'https://paulwagner.com', 'The nembutsu: the simplest Buddhist practice →', 'The nembutsu — the central practice of Pure Land Buddhism. Reciting Amitabha\'s name with sincere faith is said to ensure rebirth in the pure land.', 'lotus'),
  (187, 'ॐ अह हूँ वज्र गुरु पद्म सिद्धि हूँ', 'Om Ah Hum Vajra Guru Padma Siddhi Hum', 'Om Ah Hum — Vajra Guru — lotus-born — accomplishment — Hum.', 'buddhist', 'Mastery', 'OHM ah hoom VAHJ-rah GOO-roo PAHD-mah SID-dhee hoom', 'mantra-187.mp3', 'https://paulwagner.com', 'Padmasambhava: the lotus-born master of Tibet →', 'The mantra of Padmasambhava — Guru Rinpoche — who brought Buddhism to Tibet. The most important mantra in Vajrayana Buddhism.', 'lotus'),
  (188, 'ॐ बज्र सत्त्व हूँ', 'Om Vajrasattva Hum', 'Om — Vajrasattva — the diamond being — Hum.', 'buddhist', 'Purification', 'OHM VAHJ-rah-saht-tvah hoom', 'mantra-188.mp3', 'https://paulwagner.com', 'Vajrasattva: the 100-syllable purification practice →', 'The short mantra of Vajrasattva — the buddha of purification. Vajra means "diamond" or "thunderbolt" — indestructible and pure.', 'lotus'),
  (189, 'ॐ नमो मञ्जुश्रीये', 'Om Namo Manjushriye', 'Om, I bow to Manjushri — the bodhisattva of wisdom.', 'buddhist', 'Wisdom', 'OHM nah-MOH mahn-JOO-shree-yay', 'mantra-189.mp3', 'https://paulwagner.com', 'Manjushri\'s sword: cutting through ignorance →', 'Manjushri holds a flaming sword to cut through ignorance and a book of wisdom. He is the embodiment of prajna — transcendent wisdom.', 'lotus'),
  (190, 'ॐ अ रा पा चा ना धीः', 'Om A Ra Pa Ca Na Dhih', 'Om — the five wisdom syllables — the seed of wisdom.', 'buddhist', 'Wisdom', 'OHM ah rah pah chah nah dhee', 'mantra-190.mp3', 'https://paulwagner.com', 'The five wisdom syllables of Manjushri →', 'The mantra of Manjushri. Each syllable represents a wisdom teaching. Dhih is the seed syllable of wisdom — the most important syllable.', 'lotus'),
  (191, 'ॐ गते गते पारगते पारसंगते बोधि स्वाहा', 'Om Gate Gate Paragate Parasamgate Bodhi Svaha', 'Gone, gone, gone beyond, gone completely beyond — awakening — so be it.', 'buddhist', 'Transcendence', 'OHM GAH-tay GAH-tay pah-rah-GAH-tay pah-rah-sahm-GAH-tay BOH-dhee svah-HAH', 'mantra-191.mp3', 'https://paulwagner.com', 'The Heart Sutra: the Buddha\'s teaching on emptiness →', 'The dharani from the Heart Sutra — the most concise expression of the Buddha\'s teaching on emptiness and transcendence.', 'lotus'),
  (192, 'बुद्धं शरणं गच्छामि', 'Buddham Saranam Gacchami', 'I take refuge in the Buddha.', 'buddhist', 'Refuge', 'BOOD-dhahm shah-RAH-nahm GAHCH-chah-mee', 'mantra-192.mp3', 'https://paulwagner.com', 'The Three Jewels: the foundation of Buddhist practice →', 'The first of the Three Jewels — the triple refuge that is the foundation of all Buddhist practice. The Buddha is the awakened teacher.', 'lotus'),
  (193, 'धम्मं शरणं गच्छामि', 'Dhammam Saranam Gacchami', 'I take refuge in the Dharma — the teaching.', 'buddhist', 'Guidance', 'DHAHM-mahm shah-RAH-nahm GAHCH-chah-mee', 'mantra-193.mp3', 'https://paulwagner.com', 'The Dharma: what the Buddha actually taught →', 'The second of the Three Jewels. Dharma is the Buddha\'s teaching — the path that leads to liberation from suffering.', 'lotus'),
  (194, 'संघं शरणं गच्छामि', 'Sangham Saranam Gacchami', 'I take refuge in the Sangha — the community.', 'buddhist', 'Community', 'SAHNG-ghahm shah-RAH-nahm GAHCH-chah-mee', 'mantra-194.mp3', 'https://paulwagner.com', 'Sangha: why community is essential for awakening →', 'The third of the Three Jewels. Sangha is the community of practitioners — those who walk the path together.', 'lotus'),
  (195, 'सर्वे सत्त्वाः सुखिनो भवन्तु', 'Sarve Sattvah Sukhino Bhavantu', 'May all beings be happy.', 'buddhist', 'Loving-Kindness', 'SAHR-vay saht-TVAH soo-KHIH-noh bhah-VAHN-too', 'mantra-195.mp3', 'https://paulwagner.com', 'Metta meditation: the practice of loving-kindness →', 'The metta (loving-kindness) prayer — the foundation of Buddhist compassion practice. It begins with all beings and works inward.', 'lotus'),
  (196, 'सर्वे सत्त्वाः निरामयाः', 'Sarve Sattvah Niramayah', 'May all beings be free from suffering.', 'buddhist', 'Compassion', 'SAHR-vay saht-TVAH nih-rah-MAH-yah', 'mantra-196.mp3', 'https://paulwagner.com', 'Karuna: the practice of compassion →', 'The second line of the metta prayer. Niramaya — "free from disease" — extends to all forms of suffering, physical and mental.', 'lotus'),
  (197, 'सर्वे सत्त्वाः सुखिताः भवन्तु', 'Sarve Sattvah Sukhitah Bhavantu', 'May all beings be at ease.', 'buddhist', 'Ease', 'SAHR-vay saht-TVAH soo-KHIH-tah bhah-VAHN-too', 'mantra-197.mp3', 'https://paulwagner.com', 'Upekkha: the practice of equanimity →', 'The third line of the metta prayer. Sukhita — "at ease" — is a deeper wish than happiness: the ease of a mind free from struggle.', 'lotus'),
  (198, 'ॐ स्वस्ति प्रजाभ्यः', 'Om Svasti Prajabhyah', 'Om, may all beings be well.', 'buddhist', 'Wellbeing', 'OHM SVAHS-tee prah-JAH-bhyah', 'mantra-198.mp3', 'https://paulwagner.com', 'Svasti: the original meaning of the swastika →', 'A universal Buddhist blessing. Svasti — "well-being" — is the root of the Sanskrit word swastika, an ancient symbol of auspiciousness.', 'lotus'),
  (199, 'ॐ नमो बुद्धाय', 'Om Namo Buddhaya', 'Om, I bow to the Buddha — the awakened one.', 'buddhist', 'Awakening', 'OHM nah-MOH BOOD-dhah-yah', 'mantra-199.mp3', 'https://paulwagner.com', 'What does it mean to be awakened? →', 'A simple, direct invocation of the Buddha. Buddha means "the awakened one" — one who has seen through the illusion of the separate self.', 'lotus'),
  (200, 'ॐ नमो धर्माय', 'Om Namo Dharmaya', 'Om, I bow to the Dharma — the truth.', 'buddhist', 'Truth', 'OHM nah-MOH DHAHR-mah-yah', 'mantra-200.mp3', 'https://paulwagner.com', 'The Dharma: the Buddha\'s four noble truths →', 'Bowing to the Dharma is bowing to truth itself — the way things actually are, beyond our concepts and preferences.', 'lotus'),
  (201, 'ॐ नमो संघाय', 'Om Namo Sanghaya', 'Om, I bow to the Sangha — the community of practitioners.', 'buddhist', 'Community', 'OHM nah-MOH SAHNG-ghah-yah', 'mantra-201.mp3', 'https://paulwagner.com', 'The bodhisattva vow: awakening for all beings →', 'The sangha is not just monks — it is all beings who walk the path of awakening. We are never alone on this journey.', 'lotus'),
  (202, 'ॐ अमोघपाश हूँ', 'Om Amoghapasha Hum', 'Om — the infallible lasso of compassion — Hum.', 'buddhist', 'Compassion', 'OHM ah-MOH-ghah-PAH-shah hoom', 'mantra-202.mp3', 'https://paulwagner.com', 'Avalokiteshvara: the bodhisattva who hears all cries →', 'Amoghapasha — "infallible lasso" — is a form of Avalokiteshvara who catches all beings in the net of compassion, leaving none behind.', 'lotus'),
  (203, 'ॐ नमो भगवते अमिताभाय', 'Om Namo Bhagavate Amitabhaya', 'Om, I bow to the blessed Amitabha.', 'buddhist', 'Light', 'OHM nah-MOH bhah-gah-VAH-tay ah-mee-TAH-bhah-yah', 'mantra-203.mp3', 'https://paulwagner.com', 'The pure land: is it real or metaphorical? →', 'The full refuge mantra of Amitabha Buddha. Bhagavate — "blessed one" — is the honorific used for all buddhas.', 'lotus'),
  (204, 'ॐ मेत्ता मेत्ता मेत्ता', 'Om Metta Metta Metta', 'Om — loving-kindness, loving-kindness, loving-kindness.', 'buddhist', 'Loving-Kindness', 'OHM MET-tah MET-tah MET-tah', 'mantra-204.mp3', 'https://paulwagner.com', 'The four brahmaviharas: the divine abodes →', 'Metta (Pali) or Maitri (Sanskrit) — loving-kindness — is the first of the four brahmaviharas, the divine abodes. Triple repetition deepens the intention.', 'lotus'),
  (205, 'ॐ करुणा करुणा करुणा', 'Om Karuna Karuna Karuna', 'Om — compassion, compassion, compassion.', 'buddhist', 'Compassion', 'OHM kah-ROO-nah kah-ROO-nah kah-ROO-nah', 'mantra-205.mp3', 'https://paulwagner.com', 'Karuna: the difference between compassion and pity →', 'Karuna — compassion — is the second brahmavihara. It is the wish for all beings to be free from suffering.', 'lotus'),
  (206, 'ॐ मुदिता मुदिता मुदिता', 'Om Mudita Mudita Mudita', 'Om — sympathetic joy, sympathetic joy, sympathetic joy.', 'buddhist', 'Joy', 'OHM moo-DIH-tah moo-DIH-tah moo-DIH-tah', 'mantra-206.mp3', 'https://paulwagner.com', 'Mudita: the antidote to envy →', 'Mudita — "sympathetic joy" — is the third brahmavihara: the ability to rejoice in the happiness of others without envy.', 'lotus'),
  (207, 'ॐ उपेक्षा उपेक्षा उपेक्षा', 'Om Upekkha Upekkha Upekkha', 'Om — equanimity, equanimity, equanimity.', 'buddhist', 'Equanimity', 'OHM oo-PEK-shah oo-PEK-shah oo-PEK-shah', 'mantra-207.mp3', 'https://paulwagner.com', 'Equanimity: the highest of the four divine abodes →', 'Upekkha — equanimity — is the fourth brahmavihara: the ability to remain balanced and undisturbed in all circumstances.', 'lotus'),
  (208, 'ॐ शान्ति शान्ति शान्ति', 'Om Shanti Shanti Shanti', 'Om — peace, peace, peace.', 'buddhist', 'Peace', 'OHM SHAHN-tee SHAHN-tee SHAHN-tee', 'mantra-208.mp3', 'https://paulwagner.com', 'The three levels of peace: body, speech, and mind →', 'The universal peace invocation. Three repetitions address the three sources of disturbance: body, speech, and mind.', 'lotus'),
  (209, 'ॐ नमो रत्नत्रयाय', 'Om Namo Ratnatrayaya', 'Om, I bow to the three jewels.', 'buddhist', 'Refuge', 'OHM nah-MOH raht-nah-TRAH-yah-yah', 'mantra-209.mp3', 'https://paulwagner.com', 'Taking refuge: what it really means →', 'Ratnatraya — "three jewels" — are the Buddha, Dharma, and Sangha. Taking refuge in them is the foundation of all Buddhist practice.', 'lotus'),
  (210, 'ॐ नमो भगवते शाक्यमुनये', 'Om Namo Bhagavate Shakyamunaye', 'Om, I bow to the blessed Shakyamuni — the sage of the Shakya clan.', 'buddhist', 'Gratitude', 'OHM nah-MOH bhah-gah-VAH-tay SHAHK-yah-moo-nah-yay', 'mantra-210.mp3', 'https://paulwagner.com', 'The historical Buddha: his life and awakening →', 'Shakyamuni — "sage of the Shakyas" — is the historical Buddha, Siddhartha Gautama. This mantra honors the human teacher who showed the way.', 'lotus'),
  (211, 'ॐ अह हूँ', 'Om Ah Hum', 'Om — body, speech, mind — Hum.', 'buddhist', 'Integration', 'OHM ah hoom', 'mantra-211.mp3', 'https://paulwagner.com', 'Om Ah Hum: the three vajras of body, speech, and mind →', 'The three seed syllables of Vajrayana Buddhism: Om purifies the body, Ah purifies speech, Hum purifies the mind.', 'lotus'),
  (212, 'ॐ वज्रसत्त्व समयम्', 'Om Vajrasattva Samayam', 'Om — Vajrasattva — the sacred commitment.', 'buddhist', 'Commitment', 'OHM VAHJ-rah-saht-tvah sah-MAH-yahm', 'mantra-212.mp3', 'https://paulwagner.com', 'Samaya: the sacred vow of Vajrayana →', 'The opening of the Vajrasattva 100-syllable mantra. Samaya — "sacred commitment" — is the vow between student and teacher, between practitioner and the divine.', 'lotus'),
  (213, 'अनुपालय', 'Anupalaya', 'Please uphold me.', 'buddhist', 'Support', 'ah-noo-PAH-lah-yah', 'mantra-213.mp3', 'https://paulwagner.com', 'The 100-syllable Vajrasattva mantra: complete guide →', 'From the Vajrasattva mantra. A prayer for the divine to uphold and sustain the practitioner on the path.', 'lotus'),
  (214, 'ॐ नमो मञ्जुश्रीये नमः', 'Om Namo Manjushriye Namah', 'Om, I bow to Manjushri — the gentle-voiced one.', 'buddhist', 'Learning', 'OHM nah-MOH mahn-JOO-shree-yay nah-MAH', 'mantra-214.mp3', 'https://paulwagner.com', 'Manjushri: the bodhisattva of wisdom →', 'Manjushri — "gentle glory" — is the bodhisattva of wisdom. His name means "gentle-voiced" — wisdom is always gentle, never harsh.', 'lotus'),
  (215, 'ॐ वज्रपाणये नमः', 'Om Vajrapanaye Namah', 'Om, I bow to Vajrapani — the thunderbolt-wielder.', 'buddhist', 'Power', 'OHM VAHJ-rah-PAH-nah-yay nah-MAH', 'mantra-215.mp3', 'https://paulwagner.com', 'Vajrapani: the power of the awakened mind →', 'Vajrapani — "thunderbolt in hand" — is the bodhisattva of power. He represents the power of the awakened mind to cut through all obstacles.', 'lotus'),
  (216, 'ॐ नमो भगवते भैषज्यगुरु', 'Om Namo Bhagavate Bhaishajyaguru', 'Om, I bow to the blessed Medicine Buddha.', 'buddhist', 'Healing', 'OHM nah-MOH bhah-gah-VAH-tay bhay-SHAHJ-yah-GOO-roo', 'mantra-216.mp3', 'https://paulwagner.com', 'Medicine Buddha: the healing practice →', 'Bhaishajyaguru — "Medicine Buddha" — is the buddha of healing. His body is lapis lazuli blue, and he holds a medicine bowl.', 'lotus'),
  (217, 'वैडूर्यप्रभाराजाय', 'Vaiduryaprabharajaya', 'To the king of lapis lazuli light.', 'buddhist', 'Healing', 'vay-DOO-ryah-PRAH-bhah-RAH-jah-yah', 'mantra-217.mp3', 'https://paulwagner.com', 'Lapis lazuli: the stone of the Medicine Buddha →', 'Part of the Medicine Buddha mantra. Vaidurya — "lapis lazuli" — is the deep blue stone that represents the clarity of the awakened mind.', 'lotus'),
  (218, 'तथागताय', 'Tathagataya', 'To the thus-gone one — the one who has gone to suchness.', 'buddhist', 'Suchness', 'tah-TAH-gah-tah-yah', 'mantra-218.mp3', 'https://paulwagner.com', 'Tathata: the Buddhist concept of suchness →', 'Tathagata — "thus-gone" or "thus-come" — is the Buddha\'s own name for himself. It points to the nature of reality: things are just as they are.', 'lotus'),
  (219, 'ॐ भेकन्द्जे भेकन्द्जे', 'Om Bekandze Bekandze', 'Om — eliminate, eliminate — the pain of illness.', 'buddhist', 'Healing', 'OHM bay-KAHN-dzay bay-KAHN-dzay', 'mantra-219.mp3', 'https://paulwagner.com', 'The Medicine Buddha mantra: healing body and mind →', 'The heart of the Medicine Buddha mantra. Bekandze means "eliminate pain" — the mantra is said to heal both physical illness and the illness of ignorance.', 'lotus'),
  (220, 'महाभेकन्द्जे राद्जा समुद्गते स्वाहा', 'Maha Bekandze Radza Samudgate Svaha', 'Great elimination — king — the supreme arising — so be it.', 'buddhist', 'Complete Healing', 'mah-HAH bay-KAHN-dzay RAHD-zah sah-mood-GAH-tay svah-HAH', 'mantra-220.mp3', 'https://paulwagner.com', 'The complete Medicine Buddha practice →', 'The conclusion of the Medicine Buddha mantra. Samudgate — "supreme arising" — points to the arising of the awakened mind that heals all.', 'lotus'),
  (221, 'ॐ नमो भगवते अमितायुषे', 'Om Namo Bhagavate Amitayushe', 'Om, I bow to the blessed one of infinite life.', 'buddhist', 'Longevity', 'OHM nah-MOH bhah-gah-VAH-tay ah-mee-TAH-yoo-shay', 'mantra-221.mp3', 'https://paulwagner.com', 'Amitayus: the Buddha of infinite life →', 'Amitayus — "infinite life" — is the longevity aspect of Amitabha Buddha. This mantra is chanted for long life and the extension of the teaching.', 'lotus'),
  (222, 'ॐ अमरणि जीवन्तये स्वाहा', 'Om Amarani Jivantaye Svaha', 'Om — immortal life — living — so be it.', 'buddhist', 'Life Force', 'OHM ah-mah-RAH-nih jee-VAHN-tah-yay svah-HAH', 'mantra-222.mp3', 'https://paulwagner.com', 'The deathless: what the Buddha meant by nirvana →', 'The Amitayus mantra. Amarani — "immortal" — refers not to physical immortality but to the deathless nature of the awakened mind.', 'lotus'),
  (223, 'ॐ नमो भगवते सर्वदुर्गतिपरिशोधनाय', 'Om Namo Bhagavate Sarvadurgatiparisodhana', 'Om, I bow to the one who purifies all lower realms.', 'buddhist', 'Purification', 'OHM nah-MOH bhah-gah-VAH-tay sahr-vah-door-gah-tih-pah-rih-SOH-dhah-nah', 'mantra-223.mp3', 'https://paulwagner.com', 'The Stainless Beam mantra: purifying all karma →', 'The opening of the Stainless Beam mantra — one of the most powerful purification mantras in Tibetan Buddhism.', 'lotus'),
  (224, 'ॐ बोधिचित्त उत्पादयामि', 'Om Bodhicitta Utpadayami', 'Om, I generate the awakening mind.', 'buddhist', 'Awakening', 'OHM BOH-dhih-chiht-tah oot-PAH-dah-YAH-mih', 'mantra-224.mp3', 'https://paulwagner.com', 'Bodhicitta: the most precious mind →', 'Bodhicitta — "awakening mind" — is the aspiration to achieve enlightenment for the benefit of all beings. It is the heart of Mahayana Buddhism.', 'lotus'),
  (225, 'ॐ नमो भगवते प्रज्ञापारमिताये', 'Om Namo Bhagavate Prajnaparamitaye', 'Om, I bow to the blessed perfection of wisdom.', 'buddhist', 'Wisdom', 'OHM nah-MOH bhah-gah-VAH-tay PRAHJ-nyah-PAH-rah-mih-TAH-yay', 'mantra-225.mp3', 'https://paulwagner.com', 'Prajnaparamita: the mother of all buddhas →', 'Prajnaparamita — "perfection of wisdom" — is personified as a goddess and is the "mother of all buddhas." The Heart Sutra is her teaching.', 'lotus'),
  (226, 'ॐ नमो भगवते अक्षोभ्याय', 'Om Namo Bhagavate Akshobhyaya', 'Om, I bow to the blessed Akshobhya — the imperturbable.', 'buddhist', 'Imperturbability', 'OHM nah-MOH bhah-gah-VAH-tay ahk-SHOH-bhyah-yah', 'mantra-226.mp3', 'https://paulwagner.com', 'The five dhyani buddhas: a complete map of awakening →', 'Akshobhya — "imperturbable" — is the buddha of the east, representing mirror-like wisdom. His dark blue color represents the depth of the awakened mind.', 'lotus'),
  (227, 'ॐ नमो भगवते रत्नसम्भवाय', 'Om Namo Bhagavate Ratnasambhavaya', 'Om, I bow to the blessed Ratnasambhava — the jewel-born.', 'buddhist', 'Abundance', 'OHM nah-MOH bhah-gah-VAH-tay raht-nah-SAHM-bhah-vah-yah', 'mantra-227.mp3', 'https://paulwagner.com', 'Ratnasambhava: the wisdom of equality →', 'Ratnasambhava — "jewel-born" — is the buddha of the south, representing the wisdom of equality. All beings are equally precious jewels.', 'lotus'),
  (228, 'ॐ नमो भगवते अमोघसिद्धये', 'Om Namo Bhagavate Amoghasiddhaye', 'Om, I bow to the blessed Amoghasiddhi — the infallible accomplisher.', 'buddhist', 'Accomplishment', 'OHM nah-MOH bhah-gah-VAH-tay ah-MOH-ghah-SID-dhah-yay', 'mantra-228.mp3', 'https://paulwagner.com', 'Amoghasiddhi: the all-accomplishing wisdom →', 'Amoghasiddhi — "infallible accomplishment" — is the buddha of the north, representing all-accomplishing wisdom.', 'lotus'),
  (229, 'ॐ नमो भगवते वैरोचनाय', 'Om Namo Bhagavate Vairochana', 'Om, I bow to the blessed Vairochana — the illuminator.', 'buddhist', 'Illumination', 'OHM nah-MOH bhah-gah-VAH-tay vay-ROH-chah-nah', 'mantra-229.mp3', 'https://paulwagner.com', 'Vairochana: the central buddha of the mandala →', 'Vairochana — "the illuminator" — is the central buddha of the five dhyani buddhas, representing the dharmadhatu wisdom — the wisdom of all-encompassing space.', 'lotus'),
  (230, 'ॐ आह्राह् हूँ', 'Om Ah Ra Pa Ca Na Dhih Dhih Dhih', 'Om — the wisdom syllables — wisdom, wisdom, wisdom.', 'buddhist', 'Wisdom', 'OHM ah rah pah chah nah dhee dhee dhee', 'mantra-230.mp3', 'https://paulwagner.com', 'Prajna: the wisdom that liberates →', 'The extended Manjushri mantra with triple Dhih. Dhih is the seed syllable of wisdom — repeating it three times intensifies the awakening of prajna.', 'lotus'),
  (231, 'ॐ सुप्रतिष्ठित स्वाहा', 'Om Supratishthita Svaha', 'Om — well-established — so be it.', 'buddhist', 'Stability', 'OHM soo-prah-TISH-thih-tah svah-HAH', 'mantra-231.mp3', 'https://paulwagner.com', 'Establishing a daily practice: the Buddhist approach →', 'Supratishthita — "well-established" — is a dharani for establishing the practice firmly. Svaha seals the intention.', 'lotus'),
  (232, 'ॐ धरणी धरणी स्वाहा', 'Om Dharani Dharani Svaha', 'Om — earth-holder, earth-holder — so be it.', 'buddhist', 'Grounding', 'OHM dhah-RAH-nih dhah-RAH-nih svah-HAH', 'mantra-232.mp3', 'https://paulwagner.com', 'Dharani: the mantras that hold the earth →', 'Dharani means both "earth" and "that which holds." This mantra grounds the practice in the earth of reality.', 'lotus'),
  (233, 'ॐ नमो भगवते वज्रपाणये', 'Om Namo Bhagavate Vajrapanaye', 'Om, I bow to the blessed Vajrapani.', 'buddhist', 'Power', 'OHM nah-MOH bhah-gah-VAH-tay VAHJ-rah-PAH-nah-yay', 'mantra-233.mp3', 'https://paulwagner.com', 'The three poisons: greed, hatred, and delusion →', 'Vajrapani\'s thunderbolt cuts through the three poisons: greed, hatred, and delusion. This mantra invokes the power to overcome inner obstacles.', 'lotus'),
  (234, 'ॐ नमो भगवते कुरुकुल्लायै', 'Om Namo Bhagavate Kurukulle', 'Om, I bow to the blessed Kurukulle — the goddess of enchantment.', 'buddhist', 'Attraction', 'OHM nah-MOH bhah-gah-VAH-tay koo-roo-KOOL-lay', 'mantra-234.mp3', 'https://paulwagner.com', 'Kurukulle: the goddess who draws beings to the Dharma →', 'Kurukulle is a tantric goddess who enchants and magnetizes — drawing beings toward the Dharma through the power of love.', 'lotus'),
  (235, 'ॐ नमो भगवते चुन्द्रायै', 'Om Namo Bhagavate Cundrayai', 'Om, I bow to the blessed Cunda — the goddess of awakening.', 'buddhist', 'Awakening', 'OHM nah-MOH bhah-gah-VAH-tay CHOON-drah-yay', 'mantra-235.mp3', 'https://paulwagner.com', 'The female bodhisattvas: wisdom in feminine form →', 'Cunda (or Chunda) is a bodhisattva associated with the awakening mind. She is depicted with multiple arms representing her many activities.', 'lotus'),
  (236, 'ॐ नमो भगवते वज्रसारप्रमर्दने', 'Om Namo Bhagavate Vajrasarapramardane', 'Om, I bow to the crusher of the vajra essence.', 'buddhist', 'Purification', 'OHM nah-MOH bhah-gah-VAH-tay VAHJ-rah-SAH-rah-prah-MAHR-dah-nay', 'mantra-236.mp3', 'https://paulwagner.com', 'Karma: what it really means and how to purify it →', 'A powerful purification dharani. Pramardane — "crusher" — refers to the crushing of karmic obscurations.', 'lotus'),
  (237, 'ॐ सर्वपापविशोधन', 'Om Sarvapapavishoshana', 'Om — purifier of all sins.', 'buddhist', 'Purification', 'OHM sahr-vah-PAH-pah-vih-SOH-shah-nah', 'mantra-237.mp3', 'https://paulwagner.com', 'Purification practices in Buddhism →', 'A dharani for purifying all negative karma. Vishoshana — "drying up" — suggests that negative karma is dried up like water in sunlight.', 'lotus'),
  (238, 'ॐ नमो भगवते सर्वतथागत', 'Om Namo Bhagavate Sarvatathagata', 'Om, I bow to all the blessed thus-gone ones.', 'buddhist', 'Reverence', 'OHM nah-MOH bhah-gah-VAH-tay sahr-vah-tah-TAH-gah-tah', 'mantra-238.mp3', 'https://paulwagner.com', 'The infinite buddhas: the Buddhist vision of awakening →', 'A universal salutation to all buddhas of all times and directions. The awakened ones are infinite in number.', 'lotus'),
  (239, 'ॐ धर्मधातु स्वभाव', 'Om Dharmadhatu Svabhava', 'Om — the nature of the dharma realm.', 'buddhist', 'Nature of Mind', 'OHM DHAHR-mah-DAH-too svah-BHAH-vah', 'mantra-239.mp3', 'https://paulwagner.com', 'Dharmadhatu: the realm of truth →', 'Dharmadhatu — "dharma realm" — is the totality of all phenomena as they truly are. Svabhava — "own nature" — points to the intrinsic nature of mind.', 'lotus'),
  (240, 'ॐ स्वभाव शुद्धाः सर्वधर्माः', 'Om Svabhava Shuddha Sarvadharmah', 'Om — by nature pure are all phenomena.', 'buddhist', 'Purity', 'OHM svah-BHAH-vah SHOO-dhah sahr-vah-DHAHR-mah', 'mantra-240.mp3', 'https://paulwagner.com', 'Emptiness: the most misunderstood Buddhist teaching →', 'The emptiness mantra — all phenomena are pure by nature. This is the Madhyamaka view: nothing is inherently defiled.', 'lotus'),
  (241, 'स्वभाव शुद्धो ऽहम्', 'Svabhava Shuddho\'ham', 'I am pure by nature.', 'buddhist', 'Purity', 'svah-BHAH-vah SHOO-dhoh-hahm', 'mantra-241.mp3', 'https://paulwagner.com', 'Buddha nature: the purity that was always there →', 'The personal application of the emptiness mantra. Your true nature is pure — not because you have purified it, but because it was never defiled.', 'lotus'),
  (242, 'ॐ नमो भगवते तथागत', 'Om Namo Bhagavate Tathagata', 'Om, I bow to the blessed thus-gone one.', 'buddhist', 'Suchness', 'OHM nah-MOH bhah-gah-VAH-tay tah-TAH-gah-tah', 'mantra-242.mp3', 'https://paulwagner.com', 'Tathagata: the Buddha\'s most profound name →', 'A simple, universal invocation of the Buddha. Tathagata — "thus-gone" — points to the nature of awakening: going beyond all concepts.', 'lotus'),
  (243, 'ॐ भव भव महाभव', 'Om Bhava Bhava Mahabhava', 'Om — become, become, greatly become.', 'buddhist', 'Becoming', 'OHM BHAH-vah BHAH-vah mah-hah-BHAH-vah', 'mantra-243.mp3', 'https://paulwagner.com', 'Impermanence: the Buddhist teaching on change →', 'A mantra of transformation. Bhava — "becoming" — is the process of continuous change. The mantra invites full participation in the process of becoming.', 'lotus'),
  (244, 'ॐ सम्बोधि सम्बोधि', 'Om Sambodhi Sambodhi', 'Om — complete awakening, complete awakening.', 'buddhist', 'Awakening', 'OHM sahm-BOH-dhee sahm-BOH-dhee', 'mantra-244.mp3', 'https://paulwagner.com', 'Sambodhi: what complete awakening actually means →', 'Sambodhi — "complete awakening" — is the full enlightenment of a buddha. Repeating it twice affirms the aspiration for complete awakening.', 'lotus'),
  (245, 'ॐ बोधि बोधि महाबोधि', 'Om Bodhi Bodhi Mahabodhi', 'Om — awakening, awakening, great awakening.', 'buddhist', 'Awakening', 'OHM BOH-dhee BOH-dhee mah-hah-BOH-dhee', 'mantra-245.mp3', 'https://paulwagner.com', 'The stages of awakening in Buddhism →', 'A mantra of progressive awakening. Bodhi — "awakening" — grows from individual to great, from partial to complete.', 'lotus'),
  (246, 'ॐ नमो भगवते अवलोकितेश्वराय', 'Om Namo Bhagavate Avalokiteshvaraya', 'Om, I bow to the blessed Avalokiteshvara — the one who hears all cries.', 'buddhist', 'Compassion', 'OHM nah-MOH bhah-gah-VAH-tay ah-vah-loh-kih-TAYSH-vah-rah-yah', 'mantra-246.mp3', 'https://paulwagner.com', 'Avalokiteshvara: the bodhisattva of universal compassion →', 'Avalokiteshvara — "the one who looks down with compassion" — is the bodhisattva who hears all cries of suffering and responds with compassion.', 'lotus'),
  (247, 'ॐ सर्वज्ञाय नमः', 'Om Sarvajnaya Namah', 'Om, I bow to the all-knowing one.', 'buddhist', 'Omniscience', 'OHM sahr-VAHJ-nyah-yah nah-MAH', 'mantra-247.mp3', 'https://paulwagner.com', 'Omniscience: the Buddhist understanding →', 'Sarvajnaya — "all-knowing" — is an epithet of the Buddha. Omniscience is not supernatural; it is the natural result of a completely purified mind.', 'lotus'),
  (248, 'ॐ नमो भगवते मैत्रेयाय', 'Om Namo Bhagavate Maitreya', 'Om, I bow to the blessed Maitreya — the future Buddha of loving-kindness.', 'buddhist', 'Loving-Kindness', 'OHM nah-MOH bhah-gah-VAH-tay my-TRAY-yah', 'mantra-248.mp3', 'https://paulwagner.com', 'Maitreya: the future Buddha of loving-kindness →', 'Maitreya — "the loving one" — is the future Buddha who will appear when the Dharma has been forgotten. His name is the root of the word "metta."', 'lotus'),
  (249, 'ॐ नमो भगवते क्षितिगर्भाय', 'Om Namo Bhagavate Kshitigarbhaya', 'Om, I bow to the blessed Kshitigarbha — the earth treasury.', 'buddhist', 'Compassion', 'OHM nah-MOH bhah-gah-VAH-tay kshih-tih-GAHR-bhah-yah', 'mantra-249.mp3', 'https://paulwagner.com', 'Kshitigarbha: the bodhisattva who descends to hell →', 'Kshitigarbha — "earth treasury" — is the bodhisattva who vowed to save all beings from the hell realms before becoming a buddha.', 'lotus'),
  (250, 'ॐ सम्पद्यन्ते स्वाहा', 'Om Sampadyante Svaha', 'Om — may it be accomplished — so be it.', 'buddhist', 'Accomplishment', 'OHM sahm-PAHD-yahn-tay svah-HAH', 'mantra-250.mp3', 'https://paulwagner.com', 'Sealing a practice: the importance of dedication →', 'A completion mantra. Sampadyante — "may it be accomplished" — seals any practice or intention with the wish for its fulfillment.', 'lotus'),
  (251, 'ੴ ਸਤਿ ਨਾਮੁ', 'Ik Onkar Sat Nam', 'One God — True Name.', 'sikh', 'Unity', 'ik OHN-kahr saht nahm', 'mantra-251.mp3', 'https://paulwagner.com', 'The Mool Mantar: Sikhism\'s most sacred teaching →', 'The Mool Mantar — the root mantra of Sikhism, composed by Guru Nanak. Ik Onkar — "One God" — is the foundational truth of Sikh theology.', 'seed_of_life'),
  (252, 'ਕਰਤਾ ਪੁਰਖੁ', 'Karta Purakh', 'The Creator Being.', 'sikh', 'Creation', 'KAHR-tah POO-rahkh', 'mantra-252.mp3', 'https://paulwagner.com', 'Karta Purakh: the personal God of Sikhism →', 'From the Mool Mantar. Karta — "creator" — Purakh — "being" or "person." The divine is not an abstract force but a personal creator.', 'seed_of_life'),
  (253, 'ਨਿਰਭਉ ਨਿਰਵੈਰੁ', 'Nirbhau Nirvair', 'Without fear, without enmity.', 'sikh', 'Fearlessness', 'nih-BHOW nih-VAIR', 'mantra-253.mp3', 'https://paulwagner.com', 'Nirbhau: the fearless God of Guru Nanak →', 'From the Mool Mantar. The divine has no fear and no enemies. Meditating on these qualities transforms the practitioner.', 'seed_of_life'),
  (254, 'ਅਕਾਲ ਮੂਰਤਿ', 'Akal Murat', 'Timeless form — beyond time and death.', 'sikh', 'Eternity', 'ah-KAHL MOO-raht', 'mantra-254.mp3', 'https://paulwagner.com', 'Akal: the timeless God of Sikhism →', 'From the Mool Mantar. Akal — "beyond time" — Murat — "form." The divine is the timeless presence that underlies all temporal forms.', 'seed_of_life'),
  (255, 'ਅਜੂਨੀ ਸੈਭੰ', 'Ajuni Saibhang', 'Unborn, self-illumined.', 'sikh', 'Self-Sufficiency', 'ah-JOO-nih SAY-bhahng', 'mantra-255.mp3', 'https://paulwagner.com', 'Saibhang: the self-illumined nature of God →', 'From the Mool Mantar. The divine was not born and does not need anything outside itself. Saibhang — "self-illumined" — the divine is its own light.', 'seed_of_life'),
  (256, 'ਗੁਰ ਪ੍ਰਸਾਦਿ', 'Gur Prasad', 'By the grace of the Guru.', 'sikh', 'Grace', 'goor prah-SAHD', 'mantra-256.mp3', 'https://paulwagner.com', 'Gur Prasad: the grace that makes everything possible →', 'The final phrase of the Mool Mantar. All spiritual realization comes by the grace of the Guru — not by personal effort alone.', 'seed_of_life'),
  (257, 'ਵਾਹਿਗੁਰੂ', 'Waheguru', 'Wondrous Guru — the divine that fills us with wonder.', 'sikh', 'Wonder', 'WAH-hay-goo-roo', 'mantra-257.mp3', 'https://paulwagner.com', 'Waheguru: the wonder at the heart of Sikhism →', 'The most important mantra in Sikhism. Wahe — "wondrous" — Guru — "teacher." The divine is the teacher who fills us with wonder.', 'seed_of_life'),
  (258, 'ਸਤਿ ਨਾਮੁ ਵਾਹਿਗੁਰੂ', 'Sat Nam Waheguru', 'True Name — Wondrous Guru.', 'sikh', 'Truth', 'saht nahm WAH-hay-goo-roo', 'mantra-258.mp3', 'https://paulwagner.com', 'Sat Nam: the true name of God →', 'The most common Sikh mantra combination. Sat Nam — "True Name" — is the identity of the divine. Waheguru is the expression of wonder at that truth.', 'seed_of_life'),
  (259, 'ਸਤਿ ਸ੍ਰੀ ਅਕਾਲ', 'Sat Sri Akal', 'True, great, and timeless.', 'sikh', 'Truth', 'saht sree ah-KAHL', 'mantra-259.mp3', 'https://paulwagner.com', 'Sat Sri Akal: the Sikh greeting and its meaning →', 'The Sikh greeting and battle cry. Sri — "great" or "radiant" — Akal — "timeless." A reminder that truth is eternal.', 'seed_of_life'),
  (260, 'ਨਾਨਕ ਨਾਮ ਚੜ੍ਹਦੀ ਕਲਾ', 'Nanak Nam Chardi Kala', 'Nanak, through the Name, may there be ever-rising spirit.', 'sikh', 'Optimism', 'NAH-nahk nahm CHAHR-dee kah-LAH', 'mantra-260.mp3', 'https://paulwagner.com', 'Chardi Kala: the Sikh practice of eternal optimism →', 'Chardi Kala — "ever-rising spirit" — is the Sikh concept of eternal optimism. No matter what happens, the spirit rises. This is the Sikh response to adversity.', 'seed_of_life'),
  (261, 'ਤੇਰੇ ਭਾਣੇ ਸਰਬਤ ਦਾ ਭਲਾ', 'Tere Bhane Sarbat Da Bhala', 'In your will, may all prosper.', 'sikh', 'Universal Welfare', 'TAY-ray BHAH-nay SAHR-baht dah BHAH-lah', 'mantra-261.mp3', 'https://paulwagner.com', 'Ardas: the Sikh prayer for all humanity →', 'The Ardas prayer\'s closing line. Sarbat — "all" — Da Bhala — "welfare." The Sikh prayer always ends with a wish for the welfare of all humanity.', 'seed_of_life'),
  (262, 'ਸਿਮਰਨ ਸਿਮਰਨ ਸਿਮਰਨ', 'Simran Simran Simran', 'Remembrance, remembrance, remembrance.', 'sikh', 'Remembrance', 'SIM-rahn SIM-rahn SIM-rahn', 'mantra-262.mp3', 'https://paulwagner.com', 'Simran: the Sikh practice of divine remembrance →', 'Simran — "remembrance" or "meditation" — is the central Sikh practice. To remember God\'s name in every breath is the highest spiritual discipline.', 'seed_of_life'),
  (263, 'ਹਰਿ ਹਰਿ ਹਰਿ ਹਰਿ', 'Har Har Har Har', 'God, God, God, God — the creative infinity.', 'sikh', 'Creativity', 'hahr hahr hahr hahr', 'mantra-263.mp3', 'https://paulwagner.com', 'Har: the creative name of God in Sikhism →', 'Har is the Sikh name for God as the creative force. Repeating it activates the navel center and the creative power of the divine.', 'seed_of_life'),
  (264, 'ਹਰਿ ਨਾਮੁ ਜਪਹੁ', 'Har Nam Japahu', 'Chant the name of God.', 'sikh', 'Practice', 'hahr nahm JAH-pah-hoo', 'mantra-264.mp3', 'https://paulwagner.com', 'Japa: the practice of mantra repetition →', 'From the Guru Granth Sahib. Japahu — "chant" — is the imperative form. The Guru\'s instruction is direct: chant the name.', 'seed_of_life'),
  (265, 'ਰਾਮ ਰਾਮ ਰਾਮ ਰਾਮ', 'Ram Ram Ram Ram', 'Ram, Ram, Ram, Ram — the divine joy.', 'sikh', 'Joy', 'rahm rahm rahm rahm', 'mantra-265.mp3', 'https://paulwagner.com', 'Ram in Sikhism: the all-pervasive divine →', 'In Sikhism, Ram is not just the avatar but the divine name meaning "the one who permeates all." The Gurus used many divine names interchangeably.', 'seed_of_life'),
  (266, 'ਗੋਬਿੰਦ ਗੋਬਿੰਦ ਗੋਬਿੰਦ ਸੰਗਿ', 'Gobind Gobind Gobind Sang', 'Gobind, Gobind, Gobind — in the company of God.', 'sikh', 'Companionship', 'GOH-bind GOH-bind GOH-bind sahng', 'mantra-266.mp3', 'https://paulwagner.com', 'Sangat: the Sikh community of truth →', 'From the Guru Granth Sahib. Gobind — "sustainer of the world" — is repeated three times, then "sang" — "in the company of." We are never alone.', 'seed_of_life'),
  (267, 'ਨਾਮੁ ਜਪਤ ਅਰਪੋ ਤਨੁ ਮਨੁ', 'Nam Japat Arpo Tan Man', 'Chanting the Name, offer body and mind.', 'sikh', 'Surrender', 'nahm JAH-paht AHR-poh tahn mahn', 'mantra-267.mp3', 'https://paulwagner.com', 'Total surrender: the Sikh path of devotion →', 'From the Guru Granth Sahib. The complete offering in Sikhism is not just words but the whole self — body and mind — surrendered to the divine name.', 'seed_of_life'),
  (268, 'ਸਾਸ ਸਾਸ ਸਿਮਰਹੁ ਗੋਬਿੰਦ', 'Sas Sas Simrahu Gobind', 'With every breath, remember Gobind.', 'sikh', 'Breath Practice', 'sahs sahs SIM-rah-hoo GOH-bind', 'mantra-268.mp3', 'https://paulwagner.com', 'Breath as prayer: the Sikh practice of Sas Sas →', 'From the Guru Granth Sahib. Sas — "breath." The Sikh practice of remembering God with every breath transforms ordinary breathing into prayer.', 'seed_of_life'),
  (269, 'ਮਨ ਤੂੰ ਜੋਤਿ ਸਰੂਪੁ ਹੈ', 'Man Tu Jot Sarup Hai', 'O mind, you are the image of divine light.', 'sikh', 'Self-Realization', 'mahn too joht sah-ROOP hay', 'mantra-269.mp3', 'https://paulwagner.com', 'Jot Sarup: the light within you →', 'From the Guru Granth Sahib. Jot — "light" — Sarup — "form" or "image." The mind is not the enemy but the image of divine light.', 'seed_of_life'),
  (270, 'ਅਪਣਾ ਮੂਲੁ ਪਛਾਣੁ', 'Apna Mul Pachhan', 'Recognize your own origin.', 'sikh', 'Self-Knowledge', 'ahp-NAH mool pah-CHAHN', 'mantra-270.mp3', 'https://paulwagner.com', 'Mul: returning to the root of your being →', 'From the Guru Granth Sahib. Mul — "root" or "origin." The Guru\'s instruction: know where you come from. Your origin is divine.', 'seed_of_life'),
  (271, 'ਜਿਉ ਜਿਉ ਤੇਰੀ ਰਜਾਇ', 'Jio Jio Teri Raza', 'As is your will, so be it.', 'sikh', 'Acceptance', 'jee-OH jee-OH TAY-ree rah-ZAH', 'mantra-271.mp3', 'https://paulwagner.com', 'Raza: the Sikh practice of divine will acceptance →', 'From the Guru Granth Sahib. Raza — "will" or "pleasure." Complete acceptance of the divine will is the highest Sikh spiritual state.', 'seed_of_life'),
  (272, 'ਨਾਨਕ ਦਾਸ ਤੇਰੇ ਦਰ ਕਾ', 'Nanak Das Tere Dar Ka', 'Nanak is the servant at your door.', 'sikh', 'Humility', 'NAH-nahk dahs TAY-ray dahr kah', 'mantra-272.mp3', 'https://paulwagner.com', 'Guru Nanak: the servant who became the teacher →', 'Guru Nanak\'s signature of humility. Das — "servant." The greatest teacher called himself a servant at the divine door.', 'seed_of_life'),
  (273, 'ਤੁਧੁ ਬਿਨੁ ਦੂਜਾ ਨਾਹੀ ਕੋਇ', 'Tudh Bin Duja Nahi Koi', 'Without you, there is no other.', 'sikh', 'Oneness', 'too-DHOO bin DOO-jah nah-HEE koh-EE', 'mantra-273.mp3', 'https://paulwagner.com', 'Sikh non-dualism: there is only one →', 'From the Guru Granth Sahib. A declaration of non-duality: there is only God. Everything else is the play of the one divine reality.', 'seed_of_life'),
  (274, 'ਸਰਬ ਕਲਾ ਭਰਪੂਰ', 'Sarab Kala Bharpoor', 'Fully pervading all with all powers.', 'sikh', 'Omnipresence', 'sah-RAHB kah-LAH bhar-POOR', 'mantra-274.mp3', 'https://paulwagner.com', 'The omnipresent God of the Guru Granth Sahib →', 'From the Guru Granth Sahib. Sarab — "all" — Kala — "powers" — Bharpoor — "fully pervading." The divine is fully present everywhere with all its powers.', 'seed_of_life'),
  (275, 'ॐ', 'Om', 'The primordial sound — the vibration from which all creation arises.', 'universal', 'Source', 'OHM (hold for 5-7 seconds)', 'mantra-275.mp3', 'https://paulwagner.com', 'The physics of Om: why it is the primordial sound →', 'Om is the first sound — the vibration of pure consciousness before it becomes words or thoughts. It contains all sounds within it.', 'seed_of_life'),
  (276, 'ॐ ॐ ॐ', 'Om Om Om', 'Three Oms — for body, speech, and mind.', 'universal', 'Integration', 'OHM... OHM... OHM... (pause between each)', 'mantra-276.mp3', 'https://paulwagner.com', 'The three Oms: a complete purification practice →', 'Three Oms purify the three aspects of our being: the physical body, speech and breath, and the mind. A complete practice in three sounds.', 'seed_of_life'),
  (277, 'ॐ शान्तिः शान्तिः शान्तिः', 'Om Shantih Shantih Shantih', 'Om — peace, peace, peace.', 'universal', 'Peace', 'OHM SHAHN-tih SHAHN-tih SHAHN-tih', 'mantra-277.mp3', 'https://paulwagner.com', 'The three sources of suffering and their antidote →', 'The universal peace invocation ending all Vedic prayers. Three repetitions address the three sources of suffering: adhyatmika (self), adhibhautika (others), adhidaivika (cosmos).', 'lotus'),
  (278, 'सोऽहम्', 'So\'ham', 'I am that — the breath itself is the mantra.', 'universal', 'Identity', 'SOH-hahm (So on inhale, Ham on exhale)', 'mantra-278.mp3', 'https://paulwagner.com', 'So\'ham: the mantra you\'ve been chanting since birth →', 'So\'ham is the natural sound of the breath: So on the inhale, Ham on the exhale. The breath itself is saying "I am that" 21,600 times per day.', 'seed_of_life'),
  (279, 'हंसः', 'Hamsa', 'The swan — the breath — I am that.', 'universal', 'Breath', 'HAHM-sah (Ham on exhale, Sa on inhale)', 'mantra-279.mp3', 'https://paulwagner.com', 'Hamsa: the swan of discernment →', 'Hamsa — "swan" or "I am that" — is So\'ham reversed. The swan is the symbol of the discriminating mind that separates milk from water.', 'seed_of_life'),
  (280, 'अहम् ब्रह्मास्मि', 'Aham Brahmasmi', 'I am Brahman — I am the infinite.', 'universal', 'Self-Realization', 'AH-hahm BRAH-mahs-mih', 'mantra-280.mp3', 'https://paulwagner.com', 'The four mahavakyas: the Upanishads\' greatest declarations →', 'One of the four mahavakyas — great sayings — of the Upanishads. From the Brihadaranyaka Upanishad. The direct declaration of identity with the infinite.', 'sri_yantra'),
  (281, 'तत् त्वम् असि', 'Tat Tvam Asi', 'That thou art — you are that infinite reality.', 'universal', 'Non-Duality', 'taht tvahm AH-see', 'mantra-281.mp3', 'https://paulwagner.com', 'Tat tvam asi: the teaching that changes everything →', 'The second mahavakya from the Chandogya Upanishad. The teacher\'s declaration to the student: you are not separate from the infinite.', 'sri_yantra'),
  (282, 'प्रज्ञानं ब्रह्म', 'Prajnanam Brahma', 'Consciousness is Brahman — awareness is the infinite.', 'universal', 'Consciousness', 'PRAHJ-nyah-nahm BRAH-mah', 'mantra-282.mp3', 'https://paulwagner.com', 'Consciousness as the ground of being →', 'The third mahavakya from the Aitareya Upanishad. Prajna — "consciousness" or "awareness" — is identified with the infinite ground of being.', 'sri_yantra'),
  (283, 'अयम् आत्मा ब्रह्म', 'Ayam Atma Brahma', 'This self is Brahman — the individual self is the universal self.', 'universal', 'Unity', 'AH-yahm AHT-mah BRAH-mah', 'mantra-283.mp3', 'https://paulwagner.com', 'The four mahavakyas: the great declarations of non-duality →', 'The fourth mahavakya from the Mandukya Upanishad. The individual self (atman) is declared identical to the universal ground of being (brahman). The simplest and most direct of the four great sayings.', 'sri_yantra'),
  (284, 'ॐ पूर्णमदः पूर्णमिदम्', 'Om Purnamadah Purnamidam', 'Om — that is whole, this is whole.', 'universal', 'Wholeness', 'OHM POOR-nah-mah-dah POOR-nah-mih-dahm', 'mantra-284.mp3', 'https://paulwagner.com', 'The Isha Upanishad: the wholeness that cannot be diminished →', 'The Shanti Patha of the Isha Upanishad. The infinite is whole; the finite is also whole. When wholeness is taken from wholeness, wholeness remains.', 'seed_of_life'),
  (285, 'पूर्णात् पूर्णमुदच्यते', 'Purnat Purnamudachyate', 'From wholeness, wholeness arises.', 'universal', 'Abundance', 'POOR-naht POOR-nahm-oo-DAHCH-yah-tay', 'mantra-285.mp3', 'https://paulwagner.com', 'Infinite abundance: the Upanishadic view →', 'The second line of the Isha Upanishad Shanti Patha. The infinite gives rise to infinite worlds without being diminished.', 'seed_of_life'),
  (286, 'पूर्णस्य पूर्णमादाय पूर्णमेवावशिष्यते', 'Purnasya Purnamadaya Purnamevavashishyate', 'When wholeness is taken from wholeness, wholeness alone remains.', 'universal', 'Completeness', 'POOR-nahs-yah POOR-nahm-ah-DAH-yah POOR-nah-may-VAH-vah-shish-yah-tay', 'mantra-286.mp3', 'https://paulwagner.com', 'The mathematics of the infinite: beyond ordinary logic →', 'The complete Isha Upanishad Shanti Patha. This is the mathematics of infinity: infinity minus infinity equals infinity.', 'seed_of_life'),
  (287, 'ॐ सच्चिदानन्द', 'Om Satchidananda', 'Om — existence, consciousness, bliss.', 'universal', 'Bliss', 'OHM saht-chid-AH-nahn-dah', 'mantra-287.mp3', 'https://paulwagner.com', 'Satchidananda: the nature of ultimate reality →', 'Sat-Chit-Ananda — the three qualities of Brahman: pure existence, pure consciousness, and pure bliss. This is the nature of ultimate reality.', 'sri_yantra'),
  (288, 'ॐ नमः शिवाय', 'Om Namah Shivaya', 'Om — I bow to Shiva — the auspicious one within.', 'universal', 'Surrender', 'OHM nah-MAH shih-VAH-yah', 'mantra-288.mp3', 'https://paulwagner.com', 'The five syllables: Na Ma Shi Va Ya →', 'The Panchakshara — five-syllable mantra — is one of the most universal mantras. Na-Ma-Shi-Va-Ya represents the five elements and the five acts of Shiva.', 'sri_yantra'),
  (289, 'ॐ मणि पद्मे हूँ', 'Om Mani Padme Hum', 'Om — the jewel in the lotus — hum.', 'universal', 'Compassion', 'OHM mah-NEE pahd-MAY hoom', 'mantra-289.mp3', 'https://paulwagner.com', 'Why Om Mani Padme Hum is the most chanted mantra →', 'Returning to the most universal of all mantras. The jewel of awakened mind resting in the lotus of the world. Compassion is the universal path.', 'lotus'),
  (290, 'ॐ गं गणपतये नमः', 'Om Gam Ganapataye Namah', 'Om — seed of Ganesha — I bow to the lord of beginnings.', 'universal', 'New Beginnings', 'OHM gahm gah-nah-PAH-tah-yay nah-MAH', 'mantra-290.mp3', 'https://paulwagner.com', 'Ganesha: the remover of obstacles →', 'Ganesha is invoked at the beginning of all undertakings. Gam is his seed syllable. This mantra removes obstacles and opens new paths.', 'flower_of_life'),
  (291, 'ॐ श्रीं महालक्ष्म्यै नमः', 'Om Shrim Mahalakshmyai Namah', 'Om — seed of Lakshmi — I bow to the great Lakshmi.', 'universal', 'Abundance', 'OHM shreem mah-hah-LAHK-shmy-ay nah-MAH', 'mantra-291.mp3', 'https://paulwagner.com', 'Lakshmi: the goddess of true abundance →', 'Lakshmi is the goddess of abundance — not just material wealth but spiritual richness. Shrim is her seed syllable, the sound of prosperity.', 'lotus'),
  (292, 'ॐ ऐं सरस्वत्यै नमः', 'Om Aim Sarasvatyai Namah', 'Om — seed of Saraswati — I bow to the goddess of wisdom.', 'universal', 'Wisdom', 'OHM aim sah-rahs-VAHT-yay nah-MAH', 'mantra-292.mp3', 'https://paulwagner.com', 'Saraswati: the goddess of creative wisdom →', 'Saraswati is the goddess of learning, music, and wisdom. Aim is her seed syllable. This mantra is chanted before study and creative work.', 'lotus'),
  (293, 'ॐ दुं दुर्गायै नमः', 'Om Dum Durgayai Namah', 'Om — seed of Durga — I bow to the invincible one.', 'universal', 'Courage', 'OHM doom door-GAH-yay nah-MAH', 'mantra-293.mp3', 'https://paulwagner.com', 'Durga: the warrior goddess within you →', 'Durga — "the invincible" — is the warrior goddess who protects against all evil. Dum is her seed syllable. This mantra invokes inner strength.', 'lotus'),
  (294, 'ॐ क्लीं कृष्णाय नमः', 'Om Klim Krishnaya Namah', 'Om — seed of attraction — I bow to Krishna.', 'universal', 'Love', 'OHM kleem krish-NAH-yah nah-MAH', 'mantra-294.mp3', 'https://paulwagner.com', 'Klim: the seed syllable of divine love →', 'Klim is the seed syllable of attraction and love. This mantra invokes Krishna\'s quality of divine love — the love that draws all things toward the divine.', 'flower_of_life'),
  (295, 'ॐ नमो नारायणाय', 'Om Namo Narayanaya', 'Om — I bow to Narayana — the one who rests in all beings.', 'universal', 'Presence', 'OHM nah-MOH nah-rah-YAH-nah-yah', 'mantra-295.mp3', 'https://paulwagner.com', 'Narayana: the divine presence in all beings →', 'Narayana — "the one who rests in all beings" — is the universal form of Vishnu. This mantra recognizes the divine presence in every living being.', 'flower_of_life'),
  (296, 'ॐ तत् सत्', 'Om Tat Sat', 'Om — that — truth.', 'universal', 'Truth', 'OHM taht saht', 'mantra-296.mp3', 'https://paulwagner.com', 'Om Tat Sat: the three names of the absolute →', 'From the Bhagavad Gita. Om Tat Sat — the three designations of Brahman. Om is the sound, Tat is the pointer, Sat is the reality.', 'seed_of_life'),
  (297, 'ॐ नमो भगवते वासुदेवाय', 'Om Namo Bhagavate Vasudevaya', 'Om — I bow to the blessed Vasudeva — the all-pervading one.', 'universal', 'Pervasion', 'OHM nah-MOH bhah-gah-VAH-tay VAH-soo-DAY-vah-yah', 'mantra-297.mp3', 'https://paulwagner.com', 'The twelve-syllable mantra of Vishnu →', 'The Dvadasakshara — twelve-syllable mantra — of Vishnu. Vasudeva — "the one who dwells in all" — is the all-pervading divine.', 'flower_of_life'),
  (298, 'ॐ श्री रामाय नमः', 'Om Sri Ramaya Namah', 'Om — I bow to the radiant Ram.', 'universal', 'Virtue', 'OHM shree RAH-mah-yah nah-MAH', 'mantra-298.mp3', 'https://paulwagner.com', 'Ram: the avatar of perfect virtue →', 'Ram — "the one who delights" — is the avatar of Vishnu who embodies dharma. Sri adds radiance and auspiciousness to the invocation.', 'flower_of_life'),
  (299, 'राम राम राम', 'Ram Ram Ram', 'Ram, Ram, Ram — the name that is the Vedas.', 'universal', 'Liberation', 'rahm rahm rahm', 'mantra-299.mp3', 'https://paulwagner.com', 'Why Gandhi\'s last words were "Hey Ram" →', 'Gandhi\'s dying words were "Hey Ram." The name Ram is said to contain the essence of all the Vedas. Simple, direct, and infinitely deep.', 'flower_of_life'),
  (300, 'ॐ हनुमते नमः', 'Om Hanumate Namah', 'Om — I bow to Hanuman — the devoted servant.', 'universal', 'Devotion', 'OHM hah-noo-MAH-tay nah-MAH', 'mantra-300.mp3', 'https://paulwagner.com', 'Hanuman: the perfect devotee →', 'Hanuman is the embodiment of devotion, strength, and selfless service. His devotion to Ram is the model for all spiritual practice.', 'flower_of_life'),
  (301, 'ॐ श्री हनुमते नमः', 'Om Sri Hanumate Namah', 'Om — I bow to the radiant Hanuman.', 'universal', 'Strength', 'OHM shree hah-noo-MAH-tay nah-MAH', 'mantra-301.mp3', 'https://paulwagner.com', 'Strength through devotion: Hanuman\'s secret →', 'Hanuman\'s strength comes from his devotion — not from ego or personal power. This mantra invokes strength that is rooted in love.', 'flower_of_life'),
  (302, 'ॐ नमः शिवाय गुरवे', 'Om Namah Shivaya Gurave', 'Om — I bow to Shiva who is the Guru.', 'universal', 'Guidance', 'OHM nah-MAH shih-VAH-yah goo-RAH-vay', 'mantra-302.mp3', 'https://paulwagner.com', 'The Guru principle: the divine as teacher →', 'The opening of the Anusara yoga invocation. The Guru is not separate from Shiva — the teacher is the divine in human form.', 'sri_yantra'),
  (303, 'सच्चिदानन्द मूर्तये', 'Satchidananda Murtaye', 'Who is the embodiment of existence, consciousness, and bliss.', 'universal', 'Embodiment', 'saht-chid-AH-nahn-dah MOOR-tah-yay', 'mantra-303.mp3', 'https://paulwagner.com', 'The living embodiment of truth →', 'The second line of the Anusara invocation. The Guru embodies the three qualities of ultimate reality in human form.', 'sri_yantra'),
  (304, 'निष्प्रपञ्चाय शान्ताय', 'Nishprapanchaya Shantaya', 'Who is free from all illusion, who is peace itself.', 'universal', 'Peace', 'nish-prah-PAHN-chah-yah SHAHN-tah-yah', 'mantra-304.mp3', 'https://paulwagner.com', 'Freedom from illusion: the Guru\'s gift →', 'From the Anusara invocation. Nishprapanchaya — "free from the world of appearances." The Guru is not bound by the illusions that bind ordinary beings.', 'sri_yantra'),
  (305, 'निरालम्बाय तेजसे', 'Niralambaya Tejase', 'Who is independent of all support, who is radiance itself.', 'universal', 'Independence', 'nih-rah-LAHM-bah-yah TAY-jah-say', 'mantra-305.mp3', 'https://paulwagner.com', 'The complete Anusara invocation →', 'The final line of the Anusara invocation. The Guru needs nothing — not even our devotion. The divine is self-sufficient radiance.', 'sri_yantra'),
  (306, 'ॐ भूमि माता', 'Om Bhumi Mata', 'Om — Earth Mother.', 'universal', 'Earth', 'OHM BHOO-mih MAH-tah', 'mantra-306.mp3', 'https://paulwagner.com', 'Earth as mother: the universal teaching →', 'A universal invocation of the earth as mother. All spiritual traditions recognize the earth as sacred. We are born from her and return to her.', 'lotus'),
  (307, 'ॐ द्यौः पिता', 'Om Dyauh Pita', 'Om — Sky Father.', 'universal', 'Sky', 'OHM dyow PIH-tah', 'mantra-307.mp3', 'https://paulwagner.com', 'Sky and earth: the universal parents →', 'The sky as father — the vast, open awareness that contains all experience. The earth is our mother; the sky is our father. We are children of both.', 'flower_of_life'),
  (308, 'ॐ अन्तरिक्षम्', 'Om Antariksha', 'Om — the space between — the intermediate realm.', 'universal', 'Space', 'OHM ahn-TAH-rik-shahm', 'mantra-308.mp3', 'https://paulwagner.com', 'The space between: where transformation happens →', 'Antariksha — "the space between" — is the intermediate realm between earth and sky. It represents the liminal space of transformation.', 'seed_of_life'),
  (309, 'ॐ आकाशात् पतितं तोयम्', 'Om Akashat Patitam Toyam', 'Om — water fallen from the sky reaches the ocean.', 'universal', 'Return', 'OHM AH-kah-shaht pah-TIH-tahm TOH-yahm', 'mantra-309.mp3', 'https://paulwagner.com', 'All rivers return to the ocean: the unity of all paths →', 'A universal teaching: all rivers return to the ocean, as all prayers return to the divine. The path may differ; the destination is one.', 'seed_of_life'),
  (310, 'यथा गच्छति सागरम्', 'Yatha Gacchati Sagaram', 'So all worship reaches the one God.', 'universal', 'Unity', 'YAH-thah GAHCH-chah-tih SAH-gah-rahm', 'mantra-310.mp3', 'https://paulwagner.com', 'The unity of all religions: the perennial philosophy →', 'The second line of the universal prayer verse. Just as water always finds its way to the ocean, all sincere worship reaches the divine.', 'seed_of_life'),
  (311, 'ॐ सर्वे भवन्तु सुखिनः', 'Om Sarve Bhavantu Sukhinah', 'Om — may all be happy.', 'universal', 'Happiness', 'OHM SAHR-vay bhah-VAHN-too soo-KHIH-nah', 'mantra-311.mp3', 'https://paulwagner.com', 'The universal prayer: may all beings be happy →', 'The universal prayer for happiness. Sarve — "all" — includes all beings without exception: humans, animals, plants, and all forms of life.', 'lotus'),
  (312, 'सर्वे सन्तु निरामयाः', 'Sarve Santu Niramayah', 'May all be free from disease.', 'universal', 'Health', 'SAHR-vay SAHN-too nih-rah-MAH-yah', 'mantra-312.mp3', 'https://paulwagner.com', 'The four wishes of the universal prayer →', 'The second line of the universal prayer. Niramaya — "free from disease" — extends to all forms of suffering, not just physical illness.', 'lotus'),
  (313, 'सर्वे भद्राणि पश्यन्तु', 'Sarve Bhadrani Pashyantu', 'May all see what is auspicious.', 'universal', 'Auspiciousness', 'SAHR-vay BHAHD-rah-nih PAHSH-yahn-too', 'mantra-313.mp3', 'https://paulwagner.com', 'Seeing the auspicious: a practice of perception →', 'The third line of the universal prayer. May all beings have the eyes to see the goodness and beauty in the world.', 'lotus'),
  (314, 'मा कश्चिद् दुःखभाग् भवेत्', 'Ma Kashchid Duhkhabhag Bhavet', 'May no one suffer.', 'universal', 'Compassion', 'mah KAHSH-chid DOOH-khah-bhahg BHAH-vayt', 'mantra-314.mp3', 'https://paulwagner.com', 'The complete universal prayer: a daily practice →', 'The final line of the universal prayer. A direct, simple wish: may no being suffer. This is the essence of compassion.', 'lotus'),
  (315, 'ॐ असतो मा सद्गमय', 'Om Asato Ma Sadgamaya', 'Om — lead me from the unreal to the real.', 'universal', 'Truth', 'OHM ah-SAH-toh mah sahd-GAH-mah-yah', 'mantra-315.mp3', 'https://paulwagner.com', 'The Pavamana Mantra: the three great prayers →', 'The Pavamana Mantra from the Brihadaranyaka Upanishad. Three prayers for the three great transitions: from unreal to real, darkness to light, death to immortality.', 'sri_yantra'),
  (316, 'तमसो मा ज्योतिर्गमय', 'Tamaso Ma Jyotirgamaya', 'Lead me from darkness to light.', 'universal', 'Enlightenment', 'tah-MAH-soh mah JYOH-tir-gah-mah-yah', 'mantra-316.mp3', 'https://paulwagner.com', 'From darkness to light: the path of awakening →', 'The second line of the Pavamana Mantra. Tamas — "darkness" — is ignorance. Jyoti — "light" — is knowledge. The prayer is for the light of wisdom.', 'sri_yantra'),
  (317, 'मृत्योर्मा अमृतं गमय', 'Mrityorma Amritam Gamaya', 'Lead me from death to immortality.', 'universal', 'Immortality', 'mrih-TYOR-mah AHM-rih-tahm GAH-mah-yah', 'mantra-317.mp3', 'https://paulwagner.com', 'Amrita: the nectar of immortality →', 'The third line of the Pavamana Mantra. Mrityu — "death" — Amrita — "immortality." Not physical immortality, but the recognition of the deathless self.', 'sri_yantra'),
  (318, 'ॐ लोकाः समस्ताः सुखिनो भवन्तु', 'Om Lokah Samastah Sukhino Bhavantu', 'Om — may all beings in all worlds be happy and free.', 'universal', 'Universal Welfare', 'OHM LOH-kah sah-MAHS-tah soo-KHIH-noh bhah-VAHN-too', 'mantra-318.mp3', 'https://paulwagner.com', 'Lokah Samastah: the prayer that changes the world →', 'The most universal of all mantras. Lokah — "worlds" — Samastah — "all." This prayer extends to all beings in all dimensions of existence.', 'lotus'),
  (319, 'ॐ सर्वमंगलमांगल्ये', 'Om Sarvamangalamangalye', 'Om — the auspiciousness of all auspicious things.', 'universal', 'Auspiciousness', 'OHM sahr-vah-mahn-gah-lah-MAHN-gah-lyay', 'mantra-319.mp3', 'https://paulwagner.com', 'The divine feminine: the source of all blessings →', 'The opening of the Devi Stuti — the hymn to the goddess. The divine feminine is the source of all auspiciousness in the universe.', 'lotus'),
  (320, 'शिवे सर्वार्थसाधिके', 'Shive Sarvarthasadhike', 'O Shiva — the one who fulfills all purposes.', 'universal', 'Fulfillment', 'shih-VAY sahr-VAHR-thah-SAH-dhih-kay', 'mantra-320.mp3', 'https://paulwagner.com', 'Shiva as the divine feminine: the auspicious one →', 'The second line of the Devi Stuti. Shiva here refers to the goddess — the auspicious one who fulfills all spiritual and material purposes.', 'lotus'),
  (321, 'शरण्ये त्र्यम्बके गौरि', 'Sharanyе Tryambake Gauri', 'O refuge — three-eyed one — O Gauri.', 'universal', 'Refuge', 'shah-RAHN-yay TRYAHM-bah-kay GOW-ree', 'mantra-321.mp3', 'https://paulwagner.com', 'Gauri: the radiant goddess →', 'The third line of the Devi Stuti. Tryambake — "three-eyed" — Gauri — "the fair one." The goddess is the ultimate refuge.', 'lotus'),
  (322, 'नारायणि नमोऽस्तु ते', 'Narayani Namostu Te', 'O Narayani — may there be bowing to you.', 'universal', 'Devotion', 'nah-rah-YAH-nih nah-MOHS-too tay', 'mantra-322.mp3', 'https://paulwagner.com', 'The complete Devi Stuti: a hymn to the goddess →', 'The final line of the Devi Stuti. Narayani — the feminine form of Narayana — is the goddess as the all-pervading divine.', 'lotus'),
  (323, 'ॐ ह्रीं', 'Om Hrim', 'Om — the maya bija — the seed of divine power.', 'universal', 'Power', 'OHM hreem', 'mantra-323.mp3', 'https://paulwagner.com', 'Hrim: the seed syllable of the goddess →', 'Hrim is the bija (seed syllable) of the goddess — the sound of maya, the creative power of the divine. It is the most powerful single syllable after Om.', 'lotus'),
  (324, 'ॐ श्रीं', 'Om Shrim', 'Om — the Lakshmi bija — the seed of abundance.', 'universal', 'Abundance', 'OHM shreem', 'mantra-324.mp3', 'https://paulwagner.com', 'Shrim: the sound of abundance →', 'Shrim is the bija of Lakshmi — the sound of abundance, beauty, and grace. It attracts all forms of prosperity: material, emotional, and spiritual.', 'lotus'),
  (325, 'ॐ ऐं', 'Om Aim', 'Om — the Saraswati bija — the seed of wisdom.', 'universal', 'Wisdom', 'OHM aim (rhymes with "time")', 'mantra-325.mp3', 'https://paulwagner.com', 'Aim: the seed syllable of wisdom →', 'Aim is the bija of Saraswati — the sound of wisdom, learning, and creative intelligence. It activates the higher mind.', 'lotus'),
  (326, 'ॐ क्लीं', 'Om Klim', 'Om — the Kama bija — the seed of love and attraction.', 'universal', 'Love', 'OHM kleem', 'mantra-326.mp3', 'https://paulwagner.com', 'Klim: the seed syllable of divine love →', 'Klim is the bija of Kama — divine love and attraction. It draws all good things toward you and opens the heart to love.', 'lotus'),
  (327, 'ॐ क्रीं', 'Om Krim', 'Om — the Kali bija — the seed of transformation.', 'universal', 'Transformation', 'OHM kreem', 'mantra-327.mp3', 'https://paulwagner.com', 'Krim: the seed syllable of transformation →', 'Krim is the bija of Kali — the sound of radical transformation. It destroys what is false and reveals what is true.', 'lotus'),
  (328, 'ॐ हूँ', 'Om Hum', 'Om — the Shiva bija — the seed of fire and protection.', 'universal', 'Protection', 'OHM hoom', 'mantra-328.mp3', 'https://paulwagner.com', 'Hum: the seed syllable of fire and protection →', 'Hum is the bija of Shiva — the sound of fire, protection, and the destruction of obstacles. It is also the seed of the awakened mind in Buddhism.', 'sri_yantra'),
  (329, 'ॐ फट्', 'Om Phat', 'Om — the weapon bija — the sound that cuts through all obstacles.', 'universal', 'Cutting Through', 'OHM phaht (sharp, explosive)', 'mantra-329.mp3', 'https://paulwagner.com', 'The weapon mantras: cutting through obstacles →', 'Phat is the weapon bija — the sound of a sword cutting through obstacles. It is used at the end of protective mantras to seal and strengthen them.', 'sri_yantra'),
  (330, 'ॐ स्वाहा', 'Om Svaha', 'Om — so be it — I offer this.', 'universal', 'Offering', 'OHM svah-HAH', 'mantra-330.mp3', 'https://paulwagner.com', 'Svaha: the sound of sacred offering →', 'Svaha is the offering bija — the sound of fire sacrifice. It seals all offerings and prayers, surrendering them to the divine.', 'flower_of_life'),
  (331, 'ॐ नमः', 'Om Namah', 'Om — I bow — I offer myself.', 'universal', 'Surrender', 'OHM nah-MAH', 'mantra-331.mp3', 'https://paulwagner.com', 'Namah: the power of bowing →', 'Namah — "I bow" — is the most universal act of spiritual surrender. It is the recognition that the divine is greater than the ego.', 'flower_of_life'),
  (332, 'ॐ नमस्ते', 'Om Namaste', 'Om — I bow to the divine in you.', 'universal', 'Recognition', 'OHM nah-mahs-TAY', 'mantra-332.mp3', 'https://paulwagner.com', 'Namaste: the greeting that changes how you see the world →', 'Namaste — "I bow to the divine in you" — is the recognition that every being is a form of the divine. This is the most radical spiritual teaching.', 'flower_of_life'),
  (333, 'ॐ तत् त्वम् असि', 'Om Tat Tvam Asi', 'Om — that thou art — you are the infinite.', 'universal', 'Non-Duality', 'OHM taht tvahm AH-see', 'mantra-333.mp3', 'https://paulwagner.com', 'The teacher-student relationship in non-dual wisdom →', 'Day 333 — a triple number — for the triple teaching: the teacher (Tat), the student (Tvam), and the identity between them (Asi).', 'sri_yantra'),
  (334, 'ॐ अयम् आत्मा ब्रह्म', 'Om Ayam Atma Brahma', 'Om — this self is Brahman.', 'universal', 'Self-Realization', 'OHM AH-yahm AHT-mah BRAH-mah', 'mantra-334.mp3', 'https://paulwagner.com', 'The Mandukya Upanishad: the shortest and deepest Upanishad →', 'The Mandukya Upanishad mahavakya. This self — the one reading these words right now — is the infinite. Not after enlightenment. Now.', 'sri_yantra'),
  (335, 'ॐ प्रज्ञानं ब्रह्म', 'Om Prajnanam Brahma', 'Om — consciousness is Brahman.', 'universal', 'Consciousness', 'OHM PRAHJ-nyah-nahm BRAH-mah', 'mantra-335.mp3', 'https://paulwagner.com', 'Consciousness: the hard problem and the Upanishadic answer →', 'The Aitareya Upanishad mahavakya. The very awareness that is reading these words is the infinite. Consciousness is not produced by the brain — it is the ground of being.', 'sri_yantra'),
  (336, 'ॐ अहम् ब्रह्मास्मि', 'Om Aham Brahmasmi', 'Om — I am Brahman.', 'universal', 'Identity', 'OHM AH-hahm BRAH-mahs-mih', 'mantra-336.mp3', 'https://paulwagner.com', 'Aham Brahmasmi: the most radical statement in human history →', 'The Brihadaranyaka Upanishad mahavakya. The most direct declaration of identity with the infinite. Not a belief — a recognition.', 'sri_yantra'),
  (337, 'ॐ शिवोऽहम्', 'Om Shivoham', 'Om — I am Shiva.', 'universal', 'Identity', 'OHM shih-VOH-hahm', 'mantra-337.mp3', 'https://paulwagner.com', 'The Nirvana Shatakam: Shankara\'s song of liberation →', 'From Adi Shankaracharya\'s Nirvana Shatakam. Not "I worship Shiva" but "I am Shiva" — the direct recognition of identity with pure consciousness.', 'sri_yantra'),
  (338, 'चिदानन्दरूपः शिवोऽहम् शिवोऽहम्', 'Chidanandarupah Shivoham Shivoham', 'I am the form of consciousness and bliss — I am Shiva, I am Shiva.', 'universal', 'Bliss', 'chid-AH-nahn-dah-ROO-pah shih-VOH-hahm shih-VOH-hahm', 'mantra-338.mp3', 'https://paulwagner.com', 'The Nirvana Shatakam: the complete text →', 'The refrain of the Nirvana Shatakam. Chidanandarupah — "form of consciousness-bliss." The self is not the body, mind, or ego — it is pure conscious bliss.', 'sri_yantra'),
  (339, 'ॐ नित्यानन्द', 'Om Nityananda', 'Om — eternal bliss.', 'universal', 'Bliss', 'OHM nih-TYAH-nahn-dah', 'mantra-339.mp3', 'https://paulwagner.com', 'Nityananda: the eternal bliss that is your nature →', 'Nityananda — "eternal bliss" — is the name of several great masters. It points to the bliss that is the natural state of the self, not dependent on circumstances.', 'seed_of_life'),
  (340, 'ॐ परमानन्द', 'Om Paramananda', 'Om — supreme bliss.', 'universal', 'Supreme Joy', 'OHM pah-rah-MAH-nahn-dah', 'mantra-340.mp3', 'https://paulwagner.com', 'Ananda: the bliss that is the nature of the self →', 'Paramananda — "supreme bliss" — is the highest state of consciousness. It is not an experience that comes and goes but the very nature of pure awareness.', 'seed_of_life'),
  (341, 'ॐ सोऽहम् सोऽहम् सोऽहम्', 'Om Soham Soham Soham', 'Om — I am that, I am that, I am that.', 'universal', 'Identity', 'OHM SOH-hahm SOH-hahm SOH-hahm', 'mantra-341.mp3', 'https://paulwagner.com', 'The breath as the teacher: the Soham practice →', 'Triple Soham — the breath mantra repeated three times to deepen the recognition. With every breath, the universe is saying: "I am that."', 'seed_of_life'),
  (342, 'ॐ ब्रह्मानन्दं परमसुखदम्', 'Om Brahmananda Paramasukhadam', 'Om — the bliss of Brahman — the giver of supreme happiness.', 'universal', 'Bliss', 'OHM BRAH-mah-nahn-dahm pah-rah-mah-soo-KHAH-dahm', 'mantra-342.mp3', 'https://paulwagner.com', 'The Guru Stotram: the complete hymn to the teacher →', 'The opening of the Guru Stotram — the hymn to the Guru. The Guru is the one who gives access to the bliss of Brahman.', 'sri_yantra'),
  (343, 'केवलं ज्ञानमूर्तिम्', 'Kevalam Jnanamurtim', 'The embodiment of pure knowledge alone.', 'universal', 'Knowledge', 'KAY-vah-lahm JNYAH-nah-MOOR-tihm', 'mantra-343.mp3', 'https://paulwagner.com', 'The Guru as knowledge itself →', 'From the Guru Stotram. The Guru is not a person with knowledge — the Guru is knowledge itself in human form.', 'sri_yantra'),
  (344, 'द्वन्द्वातीतं गगनसदृशम्', 'Dvandvatitam Gaganasadrisham', 'Beyond all duality — like the sky.', 'universal', 'Non-Duality', 'dvahn-DVAH-tee-tahm GAH-gah-nah-SAH-drih-shahm', 'mantra-344.mp3', 'https://paulwagner.com', 'The sky mind: the Guru\'s consciousness →', 'From the Guru Stotram. The Guru is beyond all opposites — like the sky that contains all weather without being affected by it.', 'sri_yantra'),
  (345, 'तत्त्वमस्यादि लक्ष्यम्', 'Tattvamasyadi Laksyam', 'Whose goal is "That thou art" and similar teachings.', 'universal', 'Teaching', 'taht-tvahm-AHS-yah-dee LAHK-shyahm', 'mantra-345.mp3', 'https://paulwagner.com', 'The Guru\'s purpose: pointing to the self →', 'From the Guru Stotram. The Guru\'s purpose is to point the student toward the mahavakyas — the great teachings of identity with the infinite.', 'sri_yantra'),
  (346, 'एकं नित्यं विमलमचलम्', 'Ekam Nityam Vimalachalam', 'One, eternal, pure, and immovable.', 'universal', 'Eternity', 'AY-kahm NIH-tyahm vih-MAH-lah-CHAH-lahm', 'mantra-346.mp3', 'https://paulwagner.com', 'The four qualities of ultimate reality →', 'From the Guru Stotram. The four qualities of ultimate reality: one (not many), eternal (not temporal), pure (not defiled), immovable (not changing).', 'seed_of_life'),
  (347, 'सर्वधी साक्षिभूतम्', 'Sarvadhī Sakshibhutam', 'The witness of all minds.', 'universal', 'Witnessing', 'SAHR-vah-dhee SAHK-shih-BHOO-tahm', 'mantra-347.mp3', 'https://paulwagner.com', 'The witness: the awareness behind all experience →', 'From the Guru Stotram. The ultimate reality is the witness of all minds — the awareness that watches all thoughts without being a thought itself.', 'seed_of_life'),
  (348, 'भावातीतं त्रिगुणरहितम्', 'Bhavatitam Trigunarahitam', 'Beyond all becoming — free from the three qualities.', 'universal', 'Freedom', 'bhah-VAH-tee-tahm trih-GOO-nah-rah-HIH-tahm', 'mantra-348.mp3', 'https://paulwagner.com', 'The three gunas: the qualities of nature →', 'From the Guru Stotram. Trigunarahitam — "free from the three gunas" — the three qualities of nature: tamas, rajas, and sattva. Pure consciousness is beyond all three.', 'seed_of_life'),
  (349, 'ॐ गुरुर्ब्रह्मा गुरुर्विष्णुः', 'Om Gurur Brahma Gurur Vishnuh', 'Om — the Guru is Brahma, the Guru is Vishnu.', 'universal', 'Guru', 'OHM GOO-roor BRAH-mah GOO-roor VISH-noo', 'mantra-349.mp3', 'https://paulwagner.com', 'The Guru as the trinity: creator, sustainer, transformer →', 'The Guru Brahma Stotram. The Guru embodies all three aspects of the divine: Brahma the creator, Vishnu the sustainer, Shiva the transformer.', 'flower_of_life'),
  (350, 'गुरुर्देवो महेश्वरः', 'Gurur Devo Maheshvarah', 'The Guru is the great lord Shiva.', 'universal', 'Transformation', 'GOO-roor DAY-voh mah-HAYSH-vah-rah', 'mantra-350.mp3', 'https://paulwagner.com', 'The transforming power of the Guru →', 'The second line of the Guru Brahma Stotram. Maheshvara — "great lord" — is Shiva as the supreme transformer.', 'flower_of_life'),
  (351, 'गुरुः साक्षात् परं ब्रह्म', 'Guruh Sakshat Param Brahma', 'The Guru is directly the supreme Brahman.', 'universal', 'Identity', 'GOO-roo SAHK-shaht PAH-rahm BRAH-mah', 'mantra-351.mp3', 'https://paulwagner.com', 'The Guru as Brahman: the highest teaching →', 'The third line of the Guru Brahma Stotram. Sakshat — "directly" — the Guru is not a representative of Brahman but Brahman itself in human form.', 'flower_of_life'),
  (352, 'तस्मै श्री गुरवे नमः', 'Tasmai Sri Gurave Namah', 'To that radiant Guru — I bow.', 'universal', 'Gratitude', 'TAHS-my shree GOO-rah-vay nah-MAH', 'mantra-352.mp3', 'https://paulwagner.com', 'The complete Guru Brahma Stotram →', 'The final line of the Guru Brahma Stotram. Tasmai — "to that one." After recognizing the Guru as Brahman, the only appropriate response is bowing.', 'flower_of_life'),
  (353, 'ॐ नमो गुरवे', 'Om Namo Gurave', 'Om — I bow to the Guru.', 'universal', 'Gratitude', 'OHM nah-MOH GOO-rah-vay', 'mantra-353.mp3', 'https://paulwagner.com', 'The Guru principle: beyond the personal teacher →', 'A simple, direct bow to the teacher. The Guru is not a person — the Guru is the principle of awakening that appears in many forms.', 'flower_of_life'),
  (354, 'ॐ सर्वे भवन्तु सुखिनः सर्वे सन्तु निरामयाः', 'Om Sarve Bhavantu Sukhinah Sarve Santu Niramayah', 'Om — may all be happy — may all be free from disease.', 'universal', 'Universal Welfare', 'OHM SAHR-vay bhah-VAHN-too soo-KHIH-nah SAHR-vay SAHN-too nih-rah-MAH-yah', 'mantra-354.mp3', 'https://paulwagner.com', 'The universal prayer as a year-end practice →', 'The first two lines of the universal prayer together. As the year nears its end, we return to the most basic wish: may all be happy and free from suffering.', 'lotus'),
  (355, 'सर्वे भद्राणि पश्यन्तु मा कश्चिद् दुःखभाग् भवेत्', 'Sarve Bhadrani Pashyantu Ma Kashchid Duhkhabhag Bhavet', 'May all see what is auspicious — may no one suffer.', 'universal', 'Compassion', 'SAHR-vay BHAHD-rah-nih PAHSH-yahn-too mah KAHSH-chid DOOH-khah-bhahg BHAH-vayt', 'mantra-355.mp3', 'https://paulwagner.com', 'The complete universal prayer: a year-end reflection →', 'The final two lines of the universal prayer together. The complete prayer for all beings in four wishes.', 'lotus'),
  (356, 'ॐ लोकाः समस्ताः सुखिनो भवन्तु', 'Om Lokah Samastah Sukhino Bhavantu', 'Om — may all beings in all worlds be happy and free.', 'universal', 'Universal Welfare', 'OHM LOH-kah sah-MAHS-tah soo-KHIH-noh bhah-VAHN-too', 'mantra-356.mp3', 'https://paulwagner.com', 'Lokah Samastah: the prayer that never gets old →', 'Returning to this universal prayer as the year nears its end. Lokah — "worlds" — includes all dimensions of existence. The prayer is infinite in scope.', 'lotus'),
  (357, 'ॐ असतो मा सद्गमय तमसो मा ज्योतिर्गमय', 'Om Asato Ma Sadgamaya Tamaso Ma Jyotirgamaya', 'Om — lead me from unreal to real — from darkness to light.', 'universal', 'Awakening', 'OHM ah-SAH-toh mah sahd-GAH-mah-yah tah-MAH-soh mah JYOH-tir-gah-mah-yah', 'mantra-357.mp3', 'https://paulwagner.com', 'The Pavamana Mantra: the three great transitions →', 'The first two lines of the Pavamana Mantra together. As the year ends, we renew the prayer: lead me from what is false to what is true.', 'sri_yantra'),
  (358, 'मृत्योर्मा अमृतं गमय ॐ शान्तिः शान्तिः शान्तिः', 'Mrityorma Amritam Gamaya Om Shantih Shantih Shantih', 'Lead me from death to immortality — Om peace, peace, peace.', 'universal', 'Immortality', 'mrih-TYOR-mah AHM-rih-tahm GAH-mah-yah OHM SHAHN-tih SHAHN-tih SHAHN-tih', 'mantra-358.mp3', 'https://paulwagner.com', 'The complete Pavamana Mantra: a year-end practice →', 'The complete Pavamana Mantra with its closing peace invocation. The three prayers and the three peaces — a complete practice.', 'sri_yantra'),
  (359, 'ॐ पूर्णमदः पूर्णमिदम् पूर्णात् पूर्णमुदच्यते', 'Om Purnamadah Purnamidam Purnat Purnamudachyate', 'Om — that is whole, this is whole — from wholeness, wholeness arises.', 'universal', 'Wholeness', 'OHM POOR-nah-mah-dah POOR-nah-mih-dahm POOR-naht POOR-nahm-oo-DAHCH-yah-tay', 'mantra-359.mp3', 'https://paulwagner.com', 'Wholeness: the teaching that the year has been complete all along →', 'The first two lines of the Isha Upanishad Shanti Patha together. As the year nears completion, we contemplate the wholeness that was always here.', 'seed_of_life'),
  (360, 'पूर्णस्य पूर्णमादाय पूर्णमेवावशिष्यते ॐ शान्तिः', 'Purnasya Purnamadaya Purnamevavashishyate Om Shantih', 'When wholeness is taken from wholeness, wholeness remains — Om peace.', 'universal', 'Completeness', 'POOR-nahs-yah POOR-nahm-ah-DAH-yah POOR-nah-may-VAH-vah-shish-yah-tay OHM SHAHN-tih', 'mantra-360.mp3', 'https://paulwagner.com', 'The Isha Upanishad: the shortest and most complete Upanishad →', 'The complete Isha Upanishad Shanti Patha. 360 days — and the teaching is: nothing has been lost. You are as whole today as you were on day one.', 'seed_of_life'),
  (361, 'ॐ सच्चिदानन्द', 'Om Satchidananda', 'Om — existence, consciousness, bliss.', 'universal', 'Bliss', 'OHM saht-chid-AH-nahn-dah', 'mantra-361.mp3', 'https://paulwagner.com', 'Satchidananda: the nature of your true self →', 'Day 361 — five days from the end. Returning to the three qualities of ultimate reality. This is what you are. This is what you have always been.', 'sri_yantra'),
  (362, 'ॐ शिवोऽहम् शिवोऽहम्', 'Om Shivoham Shivoham', 'Om — I am Shiva, I am Shiva.', 'universal', 'Identity', 'OHM shih-VOH-hahm shih-VOH-hahm', 'mantra-362.mp3', 'https://paulwagner.com', 'The recognition that deepens with practice →', 'Day 362 — four days from the end. The recognition deepens: not just "I am that" but "I am Shiva" — pure consciousness, pure bliss, pure awareness.', 'sri_yantra'),
  (363, 'ॐ तत् त्वम् असि', 'Om Tat Tvam Asi', 'Om — that thou art.', 'universal', 'Non-Duality', 'OHM taht tvahm AH-see', 'mantra-363.mp3', 'https://paulwagner.com', 'Tat tvam asi: the teaching that ends all seeking →', 'Day 363 — three days from the end. The teacher\'s greatest gift: you are not separate from the infinite. You never were. You never will be.', 'sri_yantra'),
  (364, 'ॐ लोकाः समस्ताः सुखिनो भवन्तु', 'Om Lokah Samastah Sukhino Bhavantu', 'Om — may all beings in all worlds be happy and free.', 'universal', 'Universal Welfare', 'OHM LOH-kah sah-MAHS-tah soo-KHIH-noh bhah-VAHN-too', 'mantra-364.mp3', 'https://paulwagner.com', 'How a year of practice changes your prayers →', 'Day 364 — the penultimate day. After a year of practice, the prayer naturally expands: not just "may I be happy" but "may all beings be happy."', 'lotus'),
  (365, 'ॐ शान्तिः शान्तिः शान्तिः', 'Om Shantih Shantih Shantih', 'Om — peace, peace, peace.', 'universal', 'Peace', 'OHM SHAHN-tih SHAHN-tih SHAHN-tih', 'mantra-365.mp3', 'https://paulwagner.com', 'The end that is a beginning: starting the cycle again →', 'Day 365 — the final day of the year. The year began with Om and ends with peace. Three repetitions for body, speech, and mind. The practice is complete — and it begins again.', 'seed_of_life');